def initialize_sms_service(environment="sandbox"):
    """Initialize the Africa's Talking SMS service with the specified environment.
    
    Args:
        environment: Either "sandbox" or "live"
    
    Returns:
        True if initialization successful, False otherwise
    """
    global sms, SMS_ENVIRONMENT, at_username, at_api_key
    
    try:
        SMS_ENVIRONMENT = environment
        
        if environment == "sandbox":
            # Use sandbox credentials - username is fixed, but API key can be from settings
            username = "sandbox"
            api_key = at_api_key if at_api_key else "fakekey"
        else:
            # Use live credentials from settings
            username = at_username if at_username else None
            api_key = at_api_key if at_api_key else None
            
            if not username or not api_key:
                print(f"Error: Live environment selected but credentials not configured")
                return
        
        # Initialize Africa's Talking with the credentials
        africastalking.initialize(username, api_key)
        sms = africastalking.SMS
        
        print(f"SMS service initialized for {environment} environment")
        return True
        
    except Exception as e:
        print(f"Error initializing SMS service: {e}")
        return False

    


