# Font size settings
FONT_SIZE = "Normal"  # Global font size (Small, Normal, Large)

# Font size multipliers for different sizes
FONT_SIZE_MULTIPLIERS = {
    "Small": 0.85,
    "Normal": 1.0,
    "Large": 1.2
}

def get_font_size(base_size, multiplier=None):
    """Get the actual font size based on the global FONT_SIZE setting.
    
    Args:
        base_size: Base font size in points
        multiplier: Optional custom multiplier. If None, uses FONT_SIZE global setting.
    
    Returns:
        Adjusted font size as integer
    """
    if multiplier is None:
        multiplier = FONT_SIZE_MULTIPLIERS.get(FONT_SIZE, 1.0)
    return max(6, int(base_size * multiplier))  # Ensure minimum size of 6

def apply_font_size(font_size_name):
    """Apply the specified font size by updating global FONT_SIZE constant."""
    global FONT_SIZE
    
    if font_size_name in FONT_SIZE_MULTIPLIERS:
        FONT_SIZE = font_size_name
    else:
        FONT_SIZE = "Normal"

