def get_kpsea_subjects_for_grade(grade):
    """Get the list of subjects for a specific KPSEA grade.
    
    Args:
        grade: Grade number as string or int (1-6)
    
    Returns:
        List of subject names for that grade, or empty list if grade not found
    """
    return KPSEA_SUBJECT_ORDER.get(str(grade), [])


def get_subjects_for_level_and_grade(level, grade=None):
    """Return ordered subject list for the given curriculum level and optional grade."""
    if level == "KPSEA":
        if grade is None:
            return []
        try:
            cursor.execute(
                "SELECT DISTINCT s.name FROM subjects s "
                "JOIN subject_levels sl ON s.id = sl.subject_id "
                "WHERE sl.level = ? AND (sl.grade = ? OR sl.grade IS NULL) "
                "ORDER BY s.name",
                (level, int(grade))
            )
            rows = [row[0] for row in cursor.fetchall()]
            if rows:
                return rows
        except Exception:
            pass
        return get_kpsea_subjects_for_grade(grade)
    if level == "KJSEA":
        try:
            if grade is not None:
                cursor.execute(
                    "SELECT DISTINCT s.name FROM subjects s "
                    "JOIN subject_levels sl ON s.id = sl.subject_id "
                    "WHERE sl.level = ? AND sl.grade = ? "
                    "ORDER BY s.name",
                    (level, int(grade))
                )
            else:
                cursor.execute(
                    "SELECT DISTINCT s.name FROM subjects s "
                    "JOIN subject_levels sl ON s.id = sl.subject_id "
                    "WHERE sl.level = ? "
                    "ORDER BY s.name",
                    (level,)
                )
            rows = [row[0] for row in cursor.fetchall()]
            if rows:
                return rows
        except Exception:
            pass
        return KJSEA_SUBJECT_ORDER.copy()
    try:
        return KJSEA_SUBJECT_ORDER.copy()
    except Exception:
        return []

