def get_school_logo_path():
    """Get the path to the school logo, converting HEIC to PNG if necessary."""
    try:
        # Check if original logo exists
        if os.path.exists(SCHOOL_LOGO_PATH):
            # Try to convert HEIC to PNG
            png_path = os.path.join(BASE_DIR, "school_logo.png")
            
            # If PNG doesn't exist, convert it
            if not os.path.exists(png_path):
                try:
                    from PIL import Image
                    # Try to open with PIL (might fail for HEIC without pillow-heif)
                    img = Image.open(SCHOOL_LOGO_PATH)
                    # Resize logo to reasonable size
                    max_size = (200, 200)
                    img.thumbnail(max_size, Image.Resampling.LANCZOS)
                    img.save(png_path, "PNG")
                    return png_path
                except Exception as e:
                    print(f"Error converting HEIC logo: {e}")
                    # Try alternative: use system command to convert if available
                    try:
                        import subprocess
                        subprocess.run(['ffmpeg', '-i', SCHOOL_LOGO_PATH, png_path], 
                                     capture_output=True, timeout=5)
                        if os.path.exists(png_path):
                            return png_path
                    except:
                        pass
                    
                    # Last resort: check if PNG version already exists in school logo folder
                    school_logo_dir = os.path.dirname(SCHOOL_LOGO_PATH)
                    for file in os.listdir(school_logo_dir):
                        if file.lower().endswith('.png'):
                            return os.path.join(school_logo_dir, file)
                    
                    return None
            
            return png_path
        return None
    except Exception as e:
        print(f"Error getting logo path: {e}")
        return None

# Get logo path on startup
