# ================== SECURE PASSWORD MANAGEMENT ================== #

def hash_password(password, salt=None):
    """Hash a password using SHA-256 with a salt for enhanced security.
    
    Returns a string in format 'salt$hash' for storage.
    If salt is not provided, a random 32-byte salt is generated.
    """
    if salt is None:
        salt = secrets.token_hex(32)  # Generate random 64-character hex string
    
    # Combine salt and password, then hash
    password_hash = hashlib.sha256((salt + password).encode()).hexdigest()
    
    # Return combined salt and hash
    return f"{salt}${password_hash}"


def verify_password(stored_hash, input_password):
    """Verify an input password against a stored SHA-256 hash.
    
    Stored hash should be in format 'salt$hash' as returned by hash_password().
    Returns True if password matches, False otherwise.
    """
    try:
        if not stored_hash or '$' not in stored_hash:
            return False
        
        salt, stored_password_hash = stored_hash.split('$', 1)
        
        # Hash the input password with the stored salt
        input_hash = hashlib.sha256((salt + input_password).encode()).hexdigest()
        
        # Compare the hashes (constant-time comparison)
        return secrets.compare_digest(input_hash, stored_password_hash)
    except Exception as e:
        print(f"Error verifying password: {e}")
        return False


def hash_admin_password(password="admin"):
    """Create a pre-hashed admin password for the default account."""
    return hash_password(password)


# ================== CREDENTIAL FUNCTIONS ================== #

def load_credentials():
    """Load login credentials for the current teacher or first available teacher.

    Returns tuple (username, password_hash, admission_num, first_school, village).
    """
    global current_teacher_username
    try:
        conn = sqlite3.connect(DB_FILE)
        cursor = conn.cursor()

        if current_teacher_username:
            cursor.execute(
                "SELECT username, password_hash, admission_num, first_school, village FROM teachers WHERE username = ?",
                (current_teacher_username,)
            )
            db_row = cursor.fetchone()
            if db_row:
                conn.close()
                return db_row

        cursor.execute(
            "SELECT username, password_hash, admission_num, first_school, village FROM teachers ORDER BY id ASC LIMIT 1"
        )
        db_row = cursor.fetchone()
        conn.close()
        if db_row:
            return db_row
    except Exception as e:
        print(f"Error loading credentials: {e}")

    try:
        if os.path.exists(CREDENTIALS_FILE):
            with open(CREDENTIALS_FILE, 'r') as f:
                data = json.load(f)
                default_hash = hash_admin_password() if not data.get("password_hash") else data.get("password_hash")
                return (
                    data.get("username", "admin"),
                    default_hash,
                    data.get("admission_num"),
                    data.get("first_school"),
                    data.get("village"),
                )
    except Exception as e:
        print(f"Error loading legacy credentials file: {e}")

    return "admin", hash_admin_password(), None, None, None


def save_credentials(username, password, teacher_name=None, mobile_number=None, staff_number=None):
    """Save or update current teacher credentials in the database.

    If the current teacher session is set, update that teacher row.
    Otherwise fall back to legacy file-based storage.
    """
    global current_teacher_username
    try:
        teacher_info = None
        if current_teacher_username:
            teacher_info = get_teacher_info(current_teacher_username)

        if teacher_info:
            conn = sqlite3.connect(DB_FILE)
            cursor = conn.cursor()
            if password == "temp":
                cursor.execute("SELECT password_hash FROM teachers WHERE id = ?", (teacher_info['id'],))
                row = cursor.fetchone()
                password_hash = row[0] if row else teacher_info.get('password_hash')
            else:
                password_hash = hash_password(password)

            cursor.execute(
                "UPDATE teachers SET username = ?, password_hash = ?, teacher_name = ?, mobile_number = ?, staff_number = ? WHERE id = ?",
                (
                    username,
                    password_hash,
                    teacher_name if teacher_name is not None else teacher_info.get('name'),
                    mobile_number if mobile_number is not None else teacher_info.get('mobile'),
                    staff_number if staff_number is not None else teacher_info.get('staff_number'),
                    teacher_info['id']
                )
            )
            conn.commit()
            conn.close()
            current_teacher_username = username
            return True

        # Legacy fallback path for file-based credentials
        data = {}
        if os.path.exists(CREDENTIALS_FILE):
            with open(CREDENTIALS_FILE, 'r') as f:
                try:
                    data = json.load(f)
                except:
                    data = {}
        data["username"] = username
        data["password_hash"] = hash_password(password) if password != "temp" else data.get("password_hash", hash_admin_password())
        if teacher_name is not None:
            data["teacher_name"] = teacher_name
        if mobile_number is not None:
            data["mobile_number"] = mobile_number
        if staff_number is not None:
            data["staff_number"] = staff_number
        with open(CREDENTIALS_FILE, 'w') as f:
            json.dump(data, f, indent=4)
        return True
    except sqlite3.IntegrityError:
        print("Username already exists in the teachers table.")
        return False
    except Exception as e:
        print(f"Error saving credentials: {e}")
        return False


def save_teacher_credentials(username, password, teacher_name=None, mobile_number=None, staff_number=None):
    """Save teacher credentials to database with SHA-256 hashing."""
    try:
        password_hash = hash_password(password)
        conn = sqlite3.connect(DB_FILE)
        cursor = conn.cursor()
        
        cursor.execute("""
            INSERT INTO teachers (username, password_hash, teacher_name, mobile_number, staff_number)
            VALUES (?, ?, ?, ?, ?)
        """, (username, password_hash, teacher_name, mobile_number, staff_number))
        
        conn.commit()
        conn.close()
        return True
    except sqlite3.IntegrityError:
        # Username already exists
        return False
    except Exception as e:
        print(f"Error saving teacher credentials: {e}")
        return False


def update_teacher_credentials(old_username, new_username, new_password=None, teacher_name=None, mobile_number=None, staff_number=None):
    """Update an existing teacher account in the database."""
    try:
        conn = sqlite3.connect(DB_FILE)
        cursor = conn.cursor()
        cursor.execute(
            "SELECT id, password_hash, teacher_name, mobile_number, staff_number FROM teachers WHERE username = ?",
            (old_username,)
        )
        row = cursor.fetchone()
        if not row:
            conn.close()
            return False

        teacher_id, current_hash, current_name, current_mobile, current_staff = row
        password_hash = current_hash if new_password is None else hash_password(new_password)
        cursor.execute(
            "UPDATE teachers SET username = ?, password_hash = ?, teacher_name = ?, mobile_number = ?, staff_number = ? WHERE id = ?",
            (
                new_username,
                password_hash,
                teacher_name if teacher_name is not None else current_name,
                mobile_number if mobile_number is not None else current_mobile,
                staff_number if staff_number is not None else current_staff,
                teacher_id
            )
        )
        conn.commit()
        conn.close()
        return True
    except sqlite3.IntegrityError:
        print("Username already exists when updating teacher credentials.")
        return False
    except Exception as e:
        print(f"Error updating teacher credentials: {e}")
        return False


def has_default_admin_only():
    """Return True when only the default admin account exists."""
    try:
        conn = sqlite3.connect(DB_FILE)
        cursor = conn.cursor()
        cursor.execute("SELECT COUNT(*) FROM teachers")
        total = cursor.fetchone()[0]
        cursor.execute("SELECT COUNT(*) FROM teachers WHERE username = 'admin'")
        admin_count = cursor.fetchone()[0]
        conn.close()
        return total == 1 and admin_count == 1
    except Exception:
        return False


def ensure_default_teacher():
    """Create a default admin teacher account if no teacher accounts exist."""
    try:
        conn = sqlite3.connect(DB_FILE)
        cursor = conn.cursor()
        cursor.execute("SELECT COUNT(*) FROM teachers")
        count = cursor.fetchone()[0]
        if count == 0:
            cursor.execute(
                "INSERT INTO teachers (username, password_hash, teacher_name) VALUES (?, ?, ?)",
                ("admin", hash_admin_password(), "Administrator")
            )
            conn.commit()
        conn.close()
    except Exception as e:
        print(f"Error ensuring default teacher account: {e}")

def verify_teacher_credentials(username, password):
    """Verify teacher username and password against database."""
    try:
        # Use web_conn if available, otherwise create new connection
        if web_conn is not None:
            cursor = web_conn.cursor()
            cursor.execute("SELECT password_hash, teacher_name FROM teachers WHERE username = ?", (username,))
            result = cursor.fetchone()
        else:
            conn = sqlite3.connect(DB_FILE)
            cursor = conn.cursor()
            cursor.execute("SELECT password_hash, teacher_name FROM teachers WHERE username = ?", (username,))
            result = cursor.fetchone()
            conn.close()
        
        if result:
            stored_hash, teacher_name = result
            if verify_password(stored_hash, password):
                return True, teacher_name
        return False, None
    except Exception as e:
        print(f"Error verifying credentials: {e}")
        return False, None


