def generate_teacher_username():
    """Generate the next teacher username in sequence.
    Format: 12330115001, 12330115002, etc.
    """
    SCHOOL_CODE = "12330115"
    prefix = SCHOOL_CODE
    try:
        conn = sqlite3.connect(DB_FILE)
        cursor = conn.cursor()
        cursor.execute(
            "SELECT username FROM teachers WHERE username LIKE ? ORDER BY username DESC LIMIT 1",
            (f"{prefix}%",)
        )
        result = cursor.fetchone()
        conn.close()

        if result:
            existing_username = result[0]
            if existing_username.startswith(prefix):
                try:
                    seq_num = int(existing_username[len(prefix):])
                    next_seq = seq_num + 1
                except (ValueError, IndexError):
                    next_seq = 1
            else:
                next_seq = 1
        else:
            next_seq = 1

        return f"{prefix}{next_seq:03d}"
    except Exception as e:
        print(f"Error generating username: {e}")
        return f"{prefix}001"


def generate_exam_id():
    """Generate the next exam ID in sequence.
    Format: EX12330115001, EX12330115002, etc.
    """
    SCHOOL_CODE = "12330115"
    prefix = f"EX{SCHOOL_CODE}"
    try:
        conn = sqlite3.connect(DB_FILE)
        cursor = conn.cursor()
        
        # Find the highest exam number for this school
        cursor.execute("SELECT exam_id FROM exams WHERE exam_id LIKE ? ORDER BY exam_id DESC LIMIT 1", (f"{prefix}%",))
        result = cursor.fetchone()
        
        if result:
            exam_id = result[0]
            if exam_id.startswith(prefix):
                try:
                    seq_num = int(exam_id[len(prefix):])
                    next_seq = seq_num + 1
                except (ValueError, IndexError):
                    next_seq = 1
            else:
                next_seq = 1
        else:
            # First exam
            next_seq = 1
        
        conn.close()
        # Format as 3-digit sequence
        return f"{prefix}{next_seq:03d}"
    except Exception as e:
        print(f"Error generating exam ID: {e}")
        return f"{prefix}001"


