def log_user_activity(username, activity, duration="0 min", status="Success", resource="", details=""):
    """Log user activity to audit trails with comprehensive details."""
    try:
        audit_data = []
        if os.path.exists(AUDIT_TRAILS_FILE):
            with open(AUDIT_TRAILS_FILE, 'r') as f:
                try:
                    audit_data = json.load(f)
                except:
                    audit_data = []
        
        # Add new entry with full audit details
        from datetime import datetime
        # Extract action type from activity
        action_type = activity.split(" - ")[0] if " - " in activity else activity.split(":")[0]
        
        new_entry = {
            "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "user": username,
            "action_type": action_type,
            "activity": activity,
            "resource": resource,
            "status": status,
            "duration": duration,
            "details": details,
            "date": datetime.now().strftime("%Y-%m-%d"),
            "time": datetime.now().strftime("%H:%M:%S")
        }
        audit_data.append(new_entry)
        
        # Keep only last 500 entries (increased from 100)
        if len(audit_data) > 500:
            audit_data = audit_data[-500:]
        
        with open(AUDIT_TRAILS_FILE, 'w') as f:
            json.dump(audit_data, f, indent=4)
        return True
    except Exception as e:
        print(f"Error logging activity: {e}")
        return False


