# ================== MARKS TO POINTS CONVERSION ================== #

def marks_to_points(marks):
    """Convert marks to points for KJSEA ranking system.
    
    Uses the standard Kenyan grading scale:
    91-100 = 12 points
    81-90 = 11 points
    71-80 = 10 points
    61-70 = 9 points
    51-60 = 8 points
    41-50 = 7 points
    31-40 = 6 points
    21-30 = 5 points
    11-20 = 4 points
    0-10 = 3 points
    """
    if marks >= 91:
        return 12
    elif marks >= 81:
        return 11
    elif marks >= 71:
        return 10
    elif marks >= 61:
        return 9
    elif marks >= 51:
        return 8
    elif marks >= 41:
        return 7
    elif marks >= 31:
        return 6
    elif marks >= 21:
        return 5
    elif marks >= 11:
        return 4
    else:
        return 3


# ================== COLOR UTILITY FUNCTIONS ================== #

def lighten_color(hex_color, factor=0.3):
    """Lighten a hex color by a given factor (0-1).
    
    Args:
        hex_color: Hex color string (e.g., '#2ecc71')
        factor: Lightening factor (0 = no change, 1 = white)
    
    Returns:
        Lightened hex color string
    """
    # Remove # if present
    hex_color = hex_color.lstrip('#')
    
    # Convert to RGB
    r = int(hex_color[0:2], 16)
    g = int(hex_color[2:4], 16)
    b = int(hex_color[4:6], 16)
    
    # Lighten each component
    r = int(r + (255 - r) * factor)
    g = int(g + (255 - g) * factor)
    b = int(b + (255 - b) * factor)
    
    # Ensure values are within 0-255
    r = min(255, max(0, r))
    g = min(255, max(0, g))
    b = min(255, max(0, b))
    
    # Convert back to hex
    return f"#{r:02x}{g:02x}{b:02x}"


