def send_sms(phone_number, message):
    """Send an SMS message via Africa's Talking API.
    
    Args:
        phone_number: Recipient phone number (international format recommended, e.g., +254712345678)
        message: The SMS message content (max 160 characters for best delivery)
    
    Returns:
        tuple: (success: bool, reason: str)
    
    Notes:
        - SMS service must be initialized with valid credentials
        - Sandbox environment is for testing (messages not actually sent)
        - Live environment requires valid Africa's Talking account and API key
        - Phone numbers should include country code for reliability
    """
    global sms, SMS_ENVIRONMENT, at_username, at_api_key
    
    try:
        # Validate inputs
        if not phone_number or not message:
            reason = "Phone number and message are required"
            print(f"Error: {reason}")
            return False, reason
        
        # Ensure SMS service is initialized
        if sms is None:
            reason = "SMS service is not initialized"
            print(f"Error: {reason}")
            return False, reason
        
        # Validate phone number format (should start with + or number)
        phone = str(phone_number).strip()
        if not phone:
            reason = f"Invalid phone number: {phone_number}"
            print(f"Error: {reason}")
            return False, reason
        
        # Add country code if missing (assuming Kenya +254)
        if phone.startswith("0"):
            phone = "+254" + phone[1:]
        elif not phone.startswith("+") and not phone.startswith("254"):
            phone = "+254" + phone
        elif phone.startswith("254") and not phone.startswith("+"):
            phone = "+" + phone
        
        # Check if live environment requires credentials
        if SMS_ENVIRONMENT == "live":
            if not at_username or not at_api_key:
                reason = "Live SMS environment selected but credentials are not configured"
                print(f"Error: {reason}")
                return False, reason
        
        # Truncate message if too long (SMS best practice: 160 chars)
        if len(message) > 160:
            truncated_msg = message[:157] + "..."
            print(f"Warning: Message truncated from {len(message)} to {len(truncated_msg)} characters")
            message = truncated_msg
        
        # Send SMS via Africa's Talking API
        try:
            response = sms.send(message, [phone])
            sms_data = response.get('SMSMessageData', {}) if isinstance(response, dict) else {}
            message_text = sms_data.get('Message', '')
            recipients = sms_data.get('Recipients', [])

            success = False
            if recipients:
                for recipient in recipients:
                    status = str(recipient.get('status', '')).lower()
                    if status in ('sent', 'success', 'queued', 'received'):
                        success = True
                        break
            elif message_text:
                lower_msg = message_text.lower()
                if 'sent' in lower_msg or 'success' in lower_msg:
                    success = True

            if success:
                print(f"✓ SMS sent to {phone} [{SMS_ENVIRONMENT}]")
                return True, "SMS sent successfully"

            error_msg = None
            if recipients:
                error_msg = recipients[0].get('status') or recipients[0].get('message')
            if not error_msg:
                error_msg = message_text or 'Unknown error'

            reason = f"SMS failed: {error_msg}"
            print(f"✗ SMS failed for {phone}: {error_msg} [{SMS_ENVIRONMENT}]")
            return False, reason

        except Exception as api_error:
            # Handle API-specific errors
            error_str = str(api_error).lower()
            if "invalid credentials" in error_str or "authentication" in error_str:
                reason = "Invalid SMS credentials"
                print(f"Error: {reason} for {SMS_ENVIRONMENT} environment")
                print(f"  - Environment: {SMS_ENVIRONMENT}")
                print(f"  - Username: {at_username if SMS_ENVIRONMENT == 'live' else 'sandbox'}")
                print(f"  - API Key: {'***' + at_api_key[-4:] if at_api_key else '[not set]'}")
            elif "network" in error_str or "connection" in error_str:
                reason = "Network error sending SMS - check internet connection"
                print(f"Error: {reason}")
            elif "timeout" in error_str:
                reason = "SMS API timeout - server not responding"
                print(f"Error: {reason}")
            else:
                reason = f"Error sending SMS: {api_error}"
                print(reason)
            return False, reason
            
    except Exception as e:
        reason = f"Unexpected error in send_sms: {e}"
        print(reason)
        return False, reason


def get_performance_abbreviation(perf_label, level="KPSEA"):
    """Return a short performance abbreviation for SMS messages."""
    if not perf_label:
        return "N/A"
    if level == "KJSEA":
        abbr_map = {
            "Exceeding E1": "E1",
            "Exceeding E2": "E2",
            "Meeting E1": "M1",
            "Meeting E2": "M2",
            "Approaching E1": "A1",
            "Approaching E2": "A2",
            "Below E1": "B1",
            "Below E2": "B2",
        }
        return abbr_map.get(perf_label, perf_label[:3].upper())
    abbr_map = {
        "Exceeding": "EXC",
        "Meeting": "MET",
        "Approaching": "APP",
        "Below": "BLW",
    }
    return abbr_map.get(perf_label, perf_label[:3].upper())


def build_student_sms_message(exam_code, exam_id, student_id, student_name, admission_number, grade, rank):
    """Construct the parent SMS text with subject scores, performance, rank and total marks."""
    level = "KPSEA" if grade <= 6 else "KJSEA"
    subjects = get_subjects_for_level_and_grade(level, grade)
    subject_parts = []
    for subj in subjects:
        subj_display = subj.replace("\\", "/")
        cursor.execute("""
            SELECT MAX(r.marks)
            FROM results r
            JOIN subjects sb ON r.subject_id = sb.id
            WHERE r.exam_id = ? AND r.student_id = ? AND sb.name = ?
        """, (exam_id, student_id, subj))
        row = cursor.fetchone()
        marks = row[0] if row and row[0] is not None else 0
        subject_parts.append(f"{subj_display}({marks})")

    total = compute_total_marks_by_grade(exam_id, student_id, grade)
    avg_mark = round(total / len(subjects)) if subjects else 0
    perf_label = get_performance_level(avg_mark, level)
    perf_abbrev = get_performance_abbreviation(perf_label, level)
    subject_text = " ".join(subject_parts) if subject_parts else ""
    return f"{student_name} ({admission_number}) {subject_text} | {perf_abbrev} | Rank {rank} | Total {total}"


def lighten_color(hex_color, amount=0.12):
    hex_color = hex_color.lstrip('#')
    r = int(hex_color[0:2], 16)
    g = int(hex_color[2:4], 16)
    b = int(hex_color[4:6], 16)
    r = int(r + (255 - r) * amount)
    g = int(g + (255 - g) * amount)
    b = int(b + (255 - b) * amount)
    return f'#{r:02x}{g:02x}{b:02x}'

