def bind_enter_to_next_field(entry_list):
    """Bind Enter key to move focus to next field in list. Last field focuses first."""
    for i, entry in enumerate(entry_list):
        next_entry = entry_list[(i + 1) % len(entry_list)]
        entry.bind("<Return>", lambda e, ne=next_entry: ne.focus())


def get_performance_level(marks, level="KPSEA"):
    """
    Determine performance level based on marks and curriculum level
    
    KPSEA (Grades 1-6):
    75-100: Exceeding Expectation
    41-74: Meeting Expectation
    21-40: Approaching Expectation
    0-20: Below Expectation
    
    KJSEA (Grades 7-9):
    90-100: Exceeding Expectation 1 (8 points)
    75-89: Exceeding Expectation 2 (7 points)
    58-74: Meeting Expectation 1 (6 points)
    41-57: Meeting Expectation 2 (5 points)
    31-40: Approaching Expectation 1 (4 points)
    21-30: Approaching Expectation 2 (3 points)
    11-20: Below Expectation 1 (2 points)
    1-10: Below Expectation 2 (1 point)
    """
    if marks is None:
        return ("—", "—") if level == "KJSEA" else "—"
    
    marks = int(marks) if isinstance(marks, (int, float)) else 0
    
    if level == "KJSEA":
        # Return tuple of (performance_label, points)
        if marks >= 90:
            return ("Exceeding E1", "8")
        elif marks >= 75:
            return ("Exceeding E2", "7")
        elif marks >= 58:
            return ("Meeting E1", "6")
        elif marks >= 41:
            return ("Meeting E2", "5")
        elif marks >= 31:
            return ("Approaching E1", "4")
        elif marks >= 21:
            return ("Approaching E2", "3")
        elif marks >= 11:
            return ("Below E1", "2")
        else:
            return ("Below E2", "1")
    else:  # KPSEA
        # Return single string for KPSEA
        if marks >= 75:
            return "Exceeding"
        elif marks >= 41:
            return "Meeting"
        elif marks >= 21:
            return "Approaching"
        else:
            return "Below"


def generate_qr_code_image(data):
    """
    Generate a QR code image from the given data.
    Returns the image as a base64-encoded string for embedding in HTML.
    """
    if not QR_AVAILABLE:
        return None
    
    try:
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(data)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        # Convert image to base64
        img_buffer = BytesIO()
        img.save(img_buffer, format='PNG')
        img_buffer.seek(0)
        img_base64 = base64.b64encode(img_buffer.getvalue()).decode('utf-8')
        
        return f"data:image/png;base64,{img_base64}"
    except Exception as e:
        print(f"Error generating QR code: {e}")
        return None


def compute_total_points(exam_id, student_id):
    """Calculate total points using the same scale as report forms.

    This mirrors the SQL CASE used in report generation so that
    rankings and reports stay consistent.
    """
    cursor.execute("""
        SELECT SUM(CASE 
            WHEN marks >= 80 THEN 8
            WHEN marks >= 75 THEN 7
            WHEN marks >= 70 THEN 6
            WHEN marks >= 65 THEN 5
            WHEN marks >= 60 THEN 4
            WHEN marks >= 55 THEN 3
            WHEN marks >= 50 THEN 2
            WHEN marks >= 45 THEN 1
            ELSE 0 END) as total_points
        FROM results r
        WHERE r.exam_id=? AND r.student_id=?
    """, (exam_id, student_id))
    res = cursor.fetchone()
    return res[0] if res and res[0] is not None else 0


def compute_total_points(exam_id, student_id):
    """Return total KJSEA points for a student in a given exam.

    Points are calculated using the same scale used in report forms:
        80+ marks => 8
        75-79 => 7
        70-74 => 6
        65-69 => 5
        60-64 => 4
        55-59 => 3
        50-54 => 2
        45-49 => 1
        below 45 => 0

    This helper ensures both ranking and report forms use identical logic.
    """
    cursor.execute("""
        SELECT SUM(CASE 
            WHEN marks >= 80 THEN 8
            WHEN marks >= 75 THEN 7
            WHEN marks >= 70 THEN 6
            WHEN marks >= 65 THEN 5
            WHEN marks >= 60 THEN 4
            WHEN marks >= 55 THEN 3
            WHEN marks >= 50 THEN 2
            WHEN marks >= 45 THEN 1
            ELSE 0 END) as total_points
        FROM results r
        WHERE r.exam_id=? AND r.student_id=?
    """, (exam_id, student_id))
    result = cursor.fetchone()
    return result[0] if result and result[0] is not None else 0


def compute_total_marks(exam_id, student_id):
    """Return the total marks for a student in an exam."""
    cursor.execute("""
        SELECT COALESCE(SUM(max_marks),0)
        FROM (
            SELECT student_id, subject_id, MAX(marks) as max_marks
            FROM results
            WHERE exam_id=?
            GROUP BY student_id, subject_id
        ) sub
        WHERE student_id=?
    """, (exam_id, student_id))
    res = cursor.fetchone()
    return res[0] if res and res[0] is not None else 0


def compute_total_marks_by_grade(exam_id, student_id, grade):
    """Compute total marks for a student in an exam using grade-specific subjects."""
    level = "KPSEA" if grade <= 6 else "KJSEA"
    subjects = get_subjects_for_level_and_grade(level, grade)
    total = 0
    for subj in subjects:
        cursor.execute("""
            SELECT MAX(r.marks)
            FROM results r
            JOIN subjects sb ON r.subject_id = sb.id
            WHERE r.exam_id = ? AND r.student_id = ? AND sb.name = ?
        """, (exam_id, student_id, subj))
        row = cursor.fetchone()
        if row and row[0] is not None:
            total += row[0]
    return total


def compute_total_points_by_grade(exam_id, student_id, grade):
    """Compute total points for KJSEA student based on grade-specific subject list."""
    if grade > 6:
        subjects = get_subjects_for_level_and_grade("KJSEA")
        total = 0
        for subj in subjects:
            cursor.execute("""
                SELECT MAX(r.marks)
                FROM results r
                JOIN subjects sb ON r.subject_id = sb.id
                WHERE r.exam_id = ? AND r.student_id = ? AND sb.name = ?
            """, (exam_id, student_id, subj))
            row = cursor.fetchone()
            if row and row[0] is not None:
                total += marks_to_points(row[0])
        return total
    return 0


def marks_to_points(marks):
    """Convert a raw mark to the corresponding KJSEA point value (int).

    Marks should be 0-100. If the level is not KJSEA or marks is None,
    returns 0.
    """
    if marks is None:
        return 0
    # get_performance_level returns (label, points) for KJSEA
    _, pts = get_performance_level(marks, level="KJSEA")
    try:
        return int(pts)
    except Exception:
        return 0

