def create_flask_app():
    """Create and configure the Flask web application for online results."""
    global web_app, web_conn, web_cursor
    
    if not FLASK_AVAILABLE:
        return None
    
    web_app = Flask(__name__, static_folder='.')
    web_app.secret_key = secrets.token_hex(16)
    
    # Add URL encoding filter to Jinja2 environment
    from urllib.parse import quote as url_quote
    web_app.jinja_env.filters['urlencode'] = lambda s: url_quote(str(s))
    
    # Create a separate database connection for the web server
    # Allow cross-thread access since Flask runs in its own thread
    print(f"Web server connecting to database: {DB_FILE}")
    web_conn = sqlite3.connect(DB_FILE, check_same_thread=False)
    web_cursor = web_conn.cursor()
    
    # Ensure database tables and default subjects are set up for web server
    ensure_tables()
    
    # Ensure default subjects for web server
    try:
        # Check if subjects exist
        web_cursor.execute("SELECT COUNT(*) FROM subjects")
        if web_cursor.fetchone()[0] == 0:
            print("Populating subjects for web server...")
            # KPSEA subjects
            kpsea_subjects = set()
            for grade_subjects in KPSEA_SUBJECT_ORDER.values():
                kpsea_subjects.update(grade_subjects)
            
            for grade, grade_subjects in KPSEA_SUBJECT_ORDER.items():
                for subj in grade_subjects:
                    web_cursor.execute("INSERT OR IGNORE INTO subjects (name) VALUES (?)", (subj,))
                    web_cursor.execute(
                        "INSERT OR IGNORE INTO subject_levels (subject_id, level, grade) VALUES ((SELECT id FROM subjects WHERE name = ?), ?, ?)",
                        (subj, "KPSEA", int(grade))
                    )
            
            # KJSEA subjects
            for subj in KJSEA_SUBJECT_ORDER:
                web_cursor.execute("INSERT OR IGNORE INTO subjects (name) VALUES (?)", (subj,))
                web_cursor.execute("INSERT OR IGNORE INTO subject_levels (subject_id, level, grade) VALUES ((SELECT id FROM subjects WHERE name = ?), ?, ?)", (subj, "KJSEA", None))
            
            web_conn.commit()
            print("Subjects populated for web server")
    except Exception as e:
        print(f"Error populating subjects for web server: {e}")
    
    # Verify database has data
    try:
        web_cursor.execute("SELECT COUNT(*) FROM subjects")
        subject_count = web_cursor.fetchone()[0]
        web_cursor.execute("SELECT COUNT(*) FROM exams")
        exam_count = web_cursor.fetchone()[0]
        print(f"Web server database initialized: {subject_count} subjects, {exam_count} exams")
    except Exception as e:
        print(f"Error checking web database: {e}")
    
