    @web_app.route('/students/add', methods=['GET', 'POST'])
    def add_student():
        if 'username' not in session:
            return redirect(url_for('login'))

        grade = request.args.get('grade', type=int)
        stream = request.args.get('stream')
        error = None

        if request.method == 'POST':
            student_name = request.form.get('student_name', '').strip()
            admission_number = request.form.get('admission_number', '').strip()
            assessment_number = request.form.get('assessment_number', '').strip() or None
            level = request.form.get('level', '').strip() or None
            grade_value = request.form.get('grade', '').strip()
            stream_value = request.form.get('stream', '').strip() or None
            parent_phone = request.form.get('parent_phone', '').strip() or None
            parent_id = request.form.get('parent_id', '').strip() or None

            try:
                student_grade = int(grade_value) if grade_value != '' else None
            except ValueError:
                student_grade = None

            if not student_name:
                error = 'Student name is required.'
            elif not admission_number:
                error = 'Admission number is required.'
            elif parent_phone:
                phone_digits = parent_phone.replace('+', '').replace(' ', '').replace('-', '')
                if not phone_digits.isdigit():
                    error = 'Invalid parent phone number. Use digits, spaces, hyphens, or a leading +.'
                elif len(phone_digits) < 10 or len(phone_digits) > 15:
                    error = 'Parent phone must be 10-15 digits.'

            if not error:
                try:
                    web_cursor.execute(
                        "INSERT INTO students (admission_number, student_name, assessment_number, level, grade, stream, parent_phone, parent_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                        (admission_number, student_name, assessment_number, level, student_grade, stream_value, parent_phone, parent_id)
                    )
                    web_conn.commit()
                    if stream_value and student_grade is not None:
                        return redirect(url_for('students_by_stream', grade=student_grade, stream=stream_value, message='Student registered successfully!'))
                    elif student_grade is not None:
                        return redirect(url_for('students_by_grade', grade=student_grade, message='Student registered successfully!'))
                    return redirect(url_for('students_page', message='Student registered successfully!'))
                except Exception as e:
                    print(f"Error adding student: {e}")
                    error = str(e)

        else:
            error = None

        student = {
            'student_name': '',
            'admission_number': '',
            'assessment_number': '',
            'level': '',
            'grade': grade,
            'stream': stream,
            'parent_phone': '',
            'parent_id': ''
        }

        return render_template_string(ADD_STUDENT_TEMPLATE, student=student, error=error, student_grade=grade, student_stream=stream)

    @web_app.route('/students/edit/<int:student_id>', methods=['GET', 'POST'])
    def edit_student(student_id):
        if 'username' not in session:
            return redirect(url_for('login'))

        if request.method == 'POST':
            student_name = request.form.get('student_name', '').strip()
            admission_number = request.form.get('admission_number', '').strip()
            assessment_number = request.form.get('assessment_number', '').strip() or None
            level = request.form.get('level', '').strip() or None
            grade_value = request.form.get('grade', '').strip()
            stream = request.form.get('stream', '').strip() or None
            parent_phone = request.form.get('parent_phone', '').strip() or None
            parent_id = request.form.get('parent_id', '').strip() or None

            try:
                grade = int(grade_value) if grade_value != '' else None
            except ValueError:
                grade = None

            # Validate parent phone if provided
            if parent_phone:
                phone_digits = parent_phone.replace("+", "").replace(" ", "").replace("-", "")
                if not phone_digits.isdigit():
                    error = "Invalid parent phone number. Phone must contain only digits, spaces, hyphens, or a leading +"
                elif len(phone_digits) < 10 or len(phone_digits) > 15:
                    error = f"Invalid parent phone length. Phone must be 10-15 digits. You entered: {len(phone_digits)} digits"
                else:
                    error = None
            else:
                error = None

            if error:
                # Re-fetch student data for form re-display
                web_cursor.execute(
                    "SELECT id, admission_number, student_name, level, grade, stream, parent_phone, parent_id, assessment_number FROM students WHERE id = ?",
                    (student_id,)
                )
                row = web_cursor.fetchone()
                if row:
                    student = {
                        'id': row[0],
                        'admission_number': row[1],
                        'student_name': row[2],
                        'level': row[3],
                        'grade': row[4],
                        'stream': row[5],
                        'parent_phone': row[6],
                        'parent_id': row[7],
                        'assessment_number': row[8]
                    }
                return render_template_string(EDIT_STUDENT_TEMPLATE, student=student, error=error, student_grade=student.get('grade'), student_stream=student.get('stream'))

            try:
                web_cursor.execute(
                    "UPDATE students SET student_name=?, admission_number=?, assessment_number=?, level=?, grade=?, stream=?, parent_phone=?, parent_id=? WHERE id=?",
                    (student_name, admission_number, assessment_number, level, grade, stream, parent_phone, parent_id, student_id)
                )
                web_conn.commit()
                # Get the updated student info for redirect
                web_cursor.execute("SELECT grade, stream FROM students WHERE id=?", (student_id,))
                updated = web_cursor.fetchone()
                if updated:
                    return redirect(url_for('students_by_stream', grade=updated[0], stream=updated[1] or '', message='Student details updated successfully!'))
                else:
                    return redirect(url_for('students_page', message='Student details updated successfully!'))
            except Exception as e:
                print(f"Error updating student: {e}")
                error = str(e)
        else:
            error = None

        web_cursor.execute(
            "SELECT id, admission_number, student_name, level, grade, stream, parent_phone, parent_id, assessment_number FROM students WHERE id = ?",
            (student_id,)
        )
        row = web_cursor.fetchone()
        if not row:
            return "Student not found", 404

        student = {
            'id': row[0],
            'admission_number': row[1],
            'student_name': row[2],
            'level': row[3],
            'grade': row[4],
            'stream': row[5],
            'parent_phone': row[6],
            'parent_id': row[7],
            'assessment_number': row[8]
        }

        return render_template_string(EDIT_STUDENT_TEMPLATE, student=student, error=error, student_grade=student.get('grade'), student_stream=student.get('stream'))

    @web_app.route('/candidates')
    def candidates_page():
        if 'username' not in session:
            return redirect(url_for('login'))

        message = request.args.get('message')
        success = request.args.get('success', type=bool)
        
