    @web_app.route('/candidate_login', methods=['GET', 'POST'])
    def candidate_login():
        if request.method == 'POST':
            admission_number = request.form.get('admission_number', '').strip()
            student_name = request.form.get('student_name', '').strip()
            error = None

            if not admission_number:
                error = 'Admission number is required.'
            elif not student_name:
                error = 'Student name is required.'

            if not error:
                try:
                    # Verify student exists and get their details
                    web_cursor.execute("""
                        SELECT id, admission_number, student_name, grade, stream
                        FROM students
                        WHERE grade = 9 AND admission_number = ? AND student_name = ?
                    """, (admission_number, student_name))
                    student = web_cursor.fetchone()

                    if student:
                        # Create session for candidate
                        session['candidate_id'] = student[0]
                        session['candidate_admission'] = student[1]
                        session['candidate_name'] = student[2]
                        session['candidate_grade'] = student[3]
                        session['candidate_stream'] = student[4]
                        return redirect(url_for('candidate_dashboard'))
                    else:
                        error = 'Student not found. Please verify your admission number and name.'
                except Exception as e:
                    print(f"Error during candidate login: {e}")
                    error = 'An error occurred during login. Please try again.'

            return render_template_string(CANDIDATE_LOGIN_TEMPLATE, error=error)

        return render_template_string(CANDIDATE_LOGIN_TEMPLATE)

    @web_app.route('/candidate_dashboard', methods=['GET', 'POST'])
    def candidate_dashboard():
        if 'candidate_id' not in session:
            return redirect(url_for('candidate_login'))

        student_id = session.get('candidate_id')
        message = None
        success = False
        
        # Get all Grade 9 subjects (KJSEA)
        try:
            subjects_list = []
            for subject_name in KJSEA_SUBJECT_ORDER:
                # Get or create subject in database
                web_cursor.execute("SELECT id FROM subjects WHERE name = ?", (subject_name,))
                subject_row = web_cursor.fetchone()
                
                if subject_row:
                    subject_id = subject_row[0]
                else:
                    # Create subject if it doesn't exist
                    web_cursor.execute("INSERT INTO subjects (name) VALUES (?)", (subject_name,))
                    web_conn.commit()
                    subject_id = web_cursor.lastrowid
                
                # Get existing target for this subject
                web_cursor.execute("""
                    SELECT target FROM candidate_targets
                    WHERE student_id = ? AND subject_id = ?
                """, (student_id, subject_id))
                target_row = web_cursor.fetchone()
                existing_target = target_row[0] if target_row else None
                
                subjects_list.append({
                    'subject_id': subject_id,
                    'subject': subject_name,
                    'target': existing_target
                })
        except Exception as e:
            print(f"Error loading subjects: {e}")
            subjects_list = []
        
        if request.method == 'POST':
            saved_count = 0
            errors = []
            
            # Process targets for each subject
            for subject_data in subjects_list:
                subject_id = subject_data['subject_id']
                target_score = request.form.get(f'target_{subject_id}', '').strip()
                
                if target_score:
                    try:
                        target_value = float(target_score)
                        
                        if target_value < 0 or target_value > 100:
                            errors.append(f"{subject_data['subject']}: Score must be 0-100")
                        else:
                            try:
                                # Save or update target for this subject
                                web_cursor.execute("""
                                    INSERT OR REPLACE INTO candidate_targets (student_id, subject_id, target)
                                    VALUES (?, ?, ?)
                                """, (student_id, subject_id, target_value))
                                saved_count += 1
                            except Exception as e:
                                print(f"Error saving target for {subject_data['subject']}: {e}")
                                errors.append(f"Error saving {subject_data['subject']}")
                    except ValueError:
                        errors.append(f"{subject_data['subject']}: Invalid number")
            
            web_conn.commit()
            
            if errors:
                message = 'Some errors occurred: ' + ', '.join(errors)
            elif saved_count > 0:
                message = f'✓ Successfully saved targets for {saved_count} subject(s)!'
                success = True
                # Refresh existing targets
                for subject_data in subjects_list:
                    web_cursor.execute("""
                        SELECT target FROM candidate_targets
                        WHERE student_id = ? AND subject_id = ?
                    """, (student_id, subject_data['subject_id']))
                    target_row = web_cursor.fetchone()
                    subject_data['target'] = target_row[0] if target_row else None
            else:
                message = 'Please enter at least one target score'

        student = {
            'admission_number': session.get('candidate_admission'),
            'student_name': session.get('candidate_name'),
            'grade': session.get('candidate_grade'),
            'stream': session.get('candidate_stream')
        }

        # Get target data and insights
        target_data = get_candidate_targets_data(student_id)
        insights = get_target_performance_insights(student_id)

        return render_template_string(
            CANDIDATE_DASHBOARD_TEMPLATE,
            student=student,
            subjects=subjects_list,
            message=message,
            success=success,
            target_data=target_data,
            insights=insights
        )

