    @web_app.route('/notifications')
    def notifications_page():
        if 'username' not in session:
            return redirect(url_for('login'))

        sms_status = "Configured" if sms else "Not configured"
        audit_trails = load_audit_trails()
        recent_activities = audit_trails[-10:] if len(audit_trails) > 10 else audit_trails
        recent_activities.reverse()

        approval_requests = load_approval_requests()
        pending_approvals = [req for req in approval_requests if req.get('status') == 'Pending Approval']
        pending_approvals.sort(key=lambda x: x.get('requested_at', ''), reverse=True)

        pdfs = []
        uploads_record_file = os.path.join(BASE_DIR, "uploads", "pdf_uploads.json")
        if os.path.exists(uploads_record_file):
            try:
                with open(uploads_record_file, 'r') as f:
                    pdfs = json.load(f)
                pdfs.sort(key=lambda x: x.get('upload_date', ''), reverse=True)
            except Exception as e:
                print(f"Error loading PDF records: {e}")
                pdfs = []

        return render_template_string(NOTIFICATIONS_TEMPLATE, username=session['username'], pdfs=pdfs, sms_status=sms_status, recent_activities=recent_activities, pending_approvals=pending_approvals)

