    @web_app.route('/settings', methods=['GET', 'POST'])
    def settings_page():
        if 'username' not in session:
            return redirect(url_for('login'))
        
        message = None
        error = None
        
        if request.method == 'POST':
            current_password = request.form.get('current_password', '').strip()
            new_username = request.form.get('new_username', '').strip()
            new_password = request.form.get('new_password', '').strip()
            confirm_password = request.form.get('confirm_password', '').strip()
            
            # Validate input
            if not current_password or not new_username or not new_password or not confirm_password:
                error = "All fields are required."
            elif new_password != confirm_password:
                error = "New passwords do not match."
            elif len(new_password) < 6:
                error = "New password must be at least 6 characters long."
            elif new_username == session['username'] and new_password == current_password:
                error = "No changes detected. Please modify at least one field."
            else:
                # Verify current password
                if not verify_credentials(session['username'], current_password):
                    error = "Current password is incorrect."
                else:
                        existing_info = get_teacher_info(session['username'])
                        existing_teacher_name = existing_info.get('name') if existing_info else None
                        existing_mobile = existing_info.get('mobile') if existing_info else None
                        existing_staff = existing_info.get('staff_number') if existing_info else None

                        final_username = new_username if new_username else session['username']
                        final_password = new_password if new_password else None

                        if update_teacher_credentials(
                            session['username'],
                            final_username,
                            final_password,
                            existing_teacher_name,
                            existing_mobile,
                            existing_staff
                        ):
                            session['username'] = final_username
                            message = "Account settings updated successfully!"
                            log_user_activity("Teacher", f"Updated account settings - Username: {final_username}", "1 min")
        
        return render_template_string(SETTINGS_TEMPLATE, message=message, error=error, username=session.get('username', ''))

    @web_app.route('/submit_marks', methods=['GET', 'POST'])
    def submit_marks():
        if 'username' not in session:
            return redirect(url_for('login'))
        
        # Get exams, subjects, and grades for dropdowns
        try:
            web_cursor.execute("SELECT id, exam_id, name FROM exams ORDER BY created_at DESC")
            exams = web_cursor.fetchall()
            
            web_cursor.execute("""
                SELECT s.id, s.name, sl.level, sl.grade
                FROM subjects s
                LEFT JOIN subject_levels sl ON s.id = sl.subject_id
                ORDER BY s.name
            """)
            subjects_raw = web_cursor.fetchall()
            
            # Process subjects with grade info
            subjects_by_id = {}
            for subj_id, name, level, grade in subjects_raw:
                if subj_id not in subjects_by_id:
                    subjects_by_id[subj_id] = {'name': name, 'grades': set()}

                if level == 'KPSEA':
                    if grade is None:
                        subjects_by_id[subj_id]['grades'].update([1, 2, 3, 4, 5, 6])
                    else:
                        subjects_by_id[subj_id]['grades'].add(grade)
                elif level == 'KJSEA':
                    if grade is None:
                        subjects_by_id[subj_id]['grades'].update([7, 8, 9])
                    else:
                        subjects_by_id[subj_id]['grades'].add(grade)

            subjects = []
            for subj_id, details in subjects_by_id.items():
                if details['grades']:
                    subjects.append((subj_id, details['name'], sorted(details['grades'])))
            
            # Get unique grades from students table
            web_cursor.execute("SELECT DISTINCT grade FROM students ORDER BY grade")
            grades = [row[0] for row in web_cursor.fetchall()]

            # Get stream values grouped by grade from students table
            web_cursor.execute(
                "SELECT DISTINCT stream, grade FROM students WHERE stream IS NOT NULL AND stream != '' ORDER BY grade, stream"
            )
            stream_rows = web_cursor.fetchall()
            streams = []
            stream_seen = set()
            for stream_name, stream_grade in stream_rows:
                if stream_name and stream_grade is not None and (stream_name, stream_grade) not in stream_seen:
                    streams.append((stream_name, stream_grade))
                    stream_seen.add((stream_name, stream_grade))
            
            # Debug: print counts and data
            print(f"Web server: Found {len(exams)} exams, {len(subjects)} subjects, {len(grades)} grades, {len(streams)} streams")
            print(f"Grades: {grades}")
            print(f"Streams: {streams}")
            
        except Exception as e:
            print(f"Error loading data: {e}")
            import traceback
            traceback.print_exc()
            exams = []
            subjects = []
            grades = []
            streams = []
        
        if request.method == 'POST':
            exam_id = request.form.get('exam_id')
            subject_id = request.form.get('subject_id')
            grade = request.form.get('grade')
            stream = request.form.get('stream')
            
            if not exam_id or not subject_id or not grade or not stream:
                return render_template_string(
                    SUBMIT_MARKS_TEMPLATE,
                    exams=exams,
                    subjects=subjects,
                    grades=grades,
                    streams=streams,
                    selected_grade=grade,
                    selected_stream=stream,
                    selected_exam_id=exam_id,
                    selected_subject_id=subject_id,
                    error="Please select grade, stream, exam and subject"
                )
            
            # Process marks submission
            marks_submitted = 0
            for key, value in request.form.items():
                if key.startswith('marks_') and value.strip():
                    student_id = key.replace('marks_', '')
                    try:
                        marks = int(value)
                        if 0 <= marks <= 100:
                            # Check if result already exists
                            web_cursor.execute("""
                                SELECT id FROM results 
                                WHERE student_id = ? AND subject_id = ? AND exam_id = ?
                            """, (student_id, subject_id, exam_id))
                            
                            existing = web_cursor.fetchone()
                            if existing:
                                # Update existing result
                                web_cursor.execute("""
                                    UPDATE results SET marks = ?, submitted_at = CURRENT_TIMESTAMP
                                    WHERE student_id = ? AND subject_id = ? AND exam_id = ?
                                """, (marks, student_id, subject_id, exam_id))
                            else:
                                # Insert new result
                                teacher_id = session.get('teacher_id')
                                web_cursor.execute("""
                                    INSERT INTO results (student_id, subject_id, exam_id, teacher_id, marks, submitted_at)
                                    VALUES (?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
                                """, (student_id, subject_id, exam_id, teacher_id, marks))
                            marks_submitted += 1
                    except ValueError:
                        continue
            
            web_conn.commit()
            return render_template_string(
                SUBMIT_MARKS_TEMPLATE,
                exams=exams,
                subjects=subjects,
                grades=grades,
                streams=streams,
                selected_grade=grade,
                selected_stream=stream,
                selected_exam_id=exam_id,
                selected_subject_id=subject_id,
                message=f"Successfully submitted marks for {marks_submitted} students"
            )
        
        return render_template_string(
            SUBMIT_MARKS_TEMPLATE,
            exams=exams,
            subjects=subjects,
            grades=grades,
            streams=streams,
            selected_grade=None,
            selected_stream=None,
            selected_exam_id=None,
            selected_subject_id=None
        )
    
