    @web_app.route('/get_students/<exam_id>/<subject_id>')
    def get_students(exam_id, subject_id):
        if 'username' not in session:
            return {'error': 'Not authenticated'}, 401
        
        grade = request.args.get('grade')  # Get grade from query parameter
        stream = request.args.get('stream')  # Get stream from query parameter
        
        try:
            # Get students who should take this exam based on their level and available subjects
            # First check if subject has level restrictions
            web_cursor.execute("""
                SELECT sl.level FROM subject_levels sl 
                WHERE sl.subject_id = ? 
                ORDER BY sl.level
            """, (subject_id,))
            subject_levels = [row[0] for row in web_cursor.fetchall()]
            
            if subject_levels:
                # Subject is restricted to specific levels
                level_condition = "s.level IN ({})".format(','.join('?' * len(subject_levels)))
                params = subject_levels
            else:
                # Subject is available to all levels
                level_condition = "1=1"
                params = []
            
            # Add grade filter if specified
            if grade:
                level_condition += " AND s.grade = ?"
                params.append(grade)
            
            # Add stream filter if specified
            if stream:
                level_condition += " AND s.stream = ?"
                params.append(stream)
            
            query = f"""
                SELECT DISTINCT s.id, s.student_name, s.admission_number, s.level
                FROM students s
                WHERE {level_condition}
                ORDER BY s.admission_number
            """
            
            web_cursor.execute(query, params)
            students = web_cursor.fetchall()
            
            student_list = []
            for student in students:
                student_list.append({
                    'id': student[0],
                    'name': student[1],
                    'admission_number': student[2]
                })
            
            print(f"Web server: Found {len(student_list)} students for subject {subject_id}, grade {grade}")
            return {'students': student_list}
            
        except Exception as e:
            print(f"Error getting students: {e}")
            return {'error': str(e)}, 500

    @web_app.route('/api/student/<admission_number>/results')
    def api_student_results(admission_number):
        if 'username' not in session:
            return {'error': 'Not authenticated'}, 401

        try:
            # Use web_cursor if available, otherwise use main cursor
            active_cursor = web_cursor
            if active_cursor is None:
                print("WARNING: web_cursor is None in api_student_results, using main cursor as fallback")
                active_cursor = cursor
            
            active_cursor.execute("""
                SELECT s.student_name, s.admission_number, sub.name, e.name, r.marks
                FROM results r
                JOIN students s ON r.student_id = s.id
                JOIN subjects sub ON r.subject_id = sub.id
                JOIN exams e ON r.exam_id = e.id
                WHERE UPPER(TRIM(s.admission_number)) = UPPER(TRIM(?))
                ORDER BY e.created_at DESC
            """, (admission_number,))
            records = active_cursor.fetchall()

            result_data = []
            for rec in records:
                student_name, admission, subject, exam_name, marks = rec
                # Get performance with KJSEA level (returns tuple for this level)
                perf_info = get_performance_level(marks, level="KJSEA")
                label = perf_info[0] if isinstance(perf_info, tuple) else perf_info
                points = perf_info[1] if isinstance(perf_info, tuple) else ""
                result_data.append({
                    'student_name': student_name,
                    'admission_number': admission,
                    'subject': subject,
                    'exam': exam_name,
                    'marks': marks,
                    'performance': label,
                    'points': points
                })

            if not result_data:
                return {'error': 'No results found for this admission number.'}, 404

            return {'results': result_data}
        except Exception as e:
            print(f"Error in api_student_results: {e}")
            import traceback
            traceback.print_exc()
            return {'error': str(e)}, 500
    
