    @web_app.route('/track_progress')
    def track_progress():
        if 'username' not in session:
            return redirect(url_for('login'))

        exam_id = request.args.get('exam_id', type=int)
        grade = request.args.get('grade', type=int)
        stream = request.args.get('stream')
        exams = []
        grades = []
        streams = []
        subject_progress = []
        selected_exam = None
        selected_grade = None
        selected_stream = None

        try:
            web_cursor.execute("SELECT id, exam_id, name FROM exams ORDER BY created_at DESC")
            exams = [{'id': row[0], 'exam_code': row[1], 'name': row[2]} for row in web_cursor.fetchall()]

            pending_requests = load_approval_requests()
            requested_subjects = set()
            for req in pending_requests:
                if (req.get('request_type') == 'Submission Request' and
                        req.get('exam_id') == exam_id and
                        req.get('grade') == grade and
                        req.get('stream') == stream):
                    requested_subjects.add(req.get('subject_name'))

            if exam_id:
                web_cursor.execute("SELECT id, exam_id, name FROM exams WHERE id=?", (exam_id,))
                row = web_cursor.fetchone()
                if row:
                    selected_exam = {'id': row[0], 'exam_code': row[1], 'name': row[2]}
                    web_cursor.execute("""
                        SELECT DISTINCT s.grade FROM students s
                        JOIN results r ON r.student_id = s.id
                        WHERE r.exam_id = ?
                        ORDER BY s.grade
                    """, (exam_id,))
                    grades = [grade_row[0] for grade_row in web_cursor.fetchall()]

                    if grade:
                        selected_grade = grade
                        web_cursor.execute(
                            "SELECT DISTINCT stream FROM students WHERE grade=? AND stream IS NOT NULL AND stream != '' ORDER BY stream",
                            (grade,)
                        )
                        streams = [row[0] for row in web_cursor.fetchall()]

                        if stream:
                            selected_stream = stream

                        level = "KPSEA" if grade <= 6 else "KJSEA"
                        subjects = get_subjects_for_level_and_grade(level, grade)
                        if selected_stream:
                            web_cursor.execute("SELECT COUNT(*) FROM students WHERE grade=? AND stream=?", (grade, selected_stream))
                        else:
                            web_cursor.execute("SELECT COUNT(*) FROM students WHERE grade=?", (grade,))
                        total_students = web_cursor.fetchone()[0] or 0
                        for subj in subjects:
                            if selected_stream:
                                web_cursor.execute("""
                                    SELECT COUNT(DISTINCT r.student_id), MAX(r.submitted_at)
                                    FROM results r
                                    JOIN subjects sub ON sub.id = r.subject_id
                                    JOIN students s ON s.id = r.student_id
                                    WHERE r.exam_id = ? AND sub.name = ? AND s.grade = ? AND s.stream = ?
                                """, (exam_id, subj, grade, selected_stream))
                            else:
                                web_cursor.execute("""
                                    SELECT COUNT(DISTINCT r.student_id), MAX(r.submitted_at)
                                    FROM results r
                                    JOIN subjects sub ON sub.id = r.subject_id
                                    JOIN students s ON s.id = r.student_id
                                    WHERE r.exam_id = ? AND sub.name = ? AND s.grade = ?
                                """, (exam_id, subj, grade))
                            row = web_cursor.fetchone()
                            submitted_count = row[0] or 0
                            last_submitted = row[1]
                            if last_submitted:
                                try:
                                    if isinstance(last_submitted, str):
                                        last_submitted_dt = datetime.datetime.fromisoformat(last_submitted)
                                    else:
                                        last_submitted_dt = last_submitted
                                    last_submitted = last_submitted_dt.strftime("%Y-%m-%d %H:%M:%S")
                                except Exception:
                                    pass
                            subject_progress.append({
                                'subject': subj.replace('\\', '/'),
                                'submitted': submitted_count > 0,
                                'submitted_count': submitted_count,
                                'total_students': total_students,
                                'last_submitted_at': last_submitted,
                                'already_requested': subj.replace('\\', '/') in requested_subjects
                            })
        except Exception as e:
            print(f"Error loading track progress data: {e}")

        return render_template_string(TRACK_PROGRESS_TEMPLATE,
                                      username=session['username'],
                                      exams=exams,
                                      grades=grades,
                                      streams=streams,
                                      subject_progress=subject_progress,
                                      selected_exam=selected_exam,
                                      selected_grade=selected_grade,
                                      selected_stream=selected_stream)

    @web_app.route('/request_submission')
    def request_submission():
        if 'username' not in session:
            return redirect(url_for('login'))

        exam_id = request.args.get('exam_id', type=int)
        grade = request.args.get('grade', type=int)
        subject = request.args.get('subject')
        if not exam_id or not grade or not subject:
            return redirect(url_for('track_progress', exam_id=exam_id, grade=grade, stream=request.args.get('stream')))

        try:
            web_cursor.execute("SELECT exam_id, name FROM exams WHERE id=?", (exam_id,))
            row = web_cursor.fetchone()
            exam_name = row[1] if row else 'Unknown Exam'
            stream = request.args.get('stream')

            request_data = {
                'request_id': secrets.token_hex(8),
                'request_type': 'Submission Request',
                'exam_id': exam_id,
                'exam_name': exam_name,
                'grade': grade,
                'stream': stream,
                'subject_name': subject,
                'requested_by': session.get('username', 'Teacher'),
                'requested_at': datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                'status': 'Pending Approval',
                'note': f'Request submission of marks for {subject} in Grade {grade} {f"({stream})" if stream else ""} ({exam_name})'
            }
            save_approval_request(request_data)
            log_user_activity(
                session.get('username', 'Teacher'),
                f"Requested marks submission for {subject} in Grade {grade} {f'({stream})' if stream else ''} ({exam_name})",
                "0 min"
            )
        except Exception as e:
            print(f"Error creating submission request: {e}")

        return redirect(url_for('track_progress', exam_id=exam_id, grade=grade, stream=request.args.get('stream')))

    def generate_student_report(student_id):
        """Generate comprehensive student performance report"""
        try:
            # Get student basic info
            web_cursor.execute("""
                SELECT student_name, admission_number, grade, stream, level
                FROM students WHERE id = ?
            """, (student_id,))
            student_info = web_cursor.fetchone()

            if not student_info:
                return None

            student_name, admission_number, grade, stream, level = student_info

            # Get all results for this student
            web_cursor.execute("""
                SELECT sub.name as subject_name, e.name as exam_name, e.exam_id, r.marks, e.created_at
                FROM results r
                JOIN subjects sub ON r.subject_id = sub.id
                JOIN exams e ON r.exam_id = e.id
                WHERE r.student_id = ?
                ORDER BY e.created_at DESC, sub.name
            """, (student_id,))
            results = web_cursor.fetchall()

            # Group results by exam
            exams_data = {}
            subject_performance = {}

            for subject_name, exam_name, exam_id, marks, created_at in results:
                if exam_name not in exams_data:
                    exams_data[exam_name] = {
                        'exam_id': exam_id,
                        'date': created_at,
                        'subjects': [],
                        'total_marks': 0,
                        'subject_count': 0
                    }

                exams_data[exam_name]['subjects'].append({
                    'subject': subject_name,
                    'marks': marks
                })
                exams_data[exam_name]['total_marks'] += marks
                exams_data[exam_name]['subject_count'] += 1

                # Track subject performance
                if subject_name not in subject_performance:
                    subject_performance[subject_name] = []
                subject_performance[subject_name].append(marks)

            # Calculate averages and statistics
            for exam_name, exam_data in exams_data.items():
                if exam_data['subject_count'] > 0:
                    exam_data['average'] = round(exam_data['total_marks'] / exam_data['subject_count'], 1)
                else:
                    exam_data['average'] = 0

            # Calculate subject averages
            subject_stats = {}
            for subject, marks_list in subject_performance.items():
                subject_stats[subject] = {
                    'average': round(sum(marks_list) / len(marks_list), 1),
                    'highest': max(marks_list),
                    'lowest': min(marks_list),
                    'attempts': len(marks_list)
                }

            # Overall statistics
            all_marks = [marks for _, _, _, marks, _ in results]
            overall_stats = {}
            if all_marks:
                overall_stats = {
                    'total_exams': len(exams_data),
                    'total_subjects': len(subject_performance),
                    'overall_average': round(sum(all_marks) / len(all_marks), 1),
                    'highest_mark': max(all_marks),
                    'lowest_mark': min(all_marks),
                    'total_marks': sum(all_marks)
                }

                # Grade distribution
                grade_distribution = {'A': 0, 'B': 0, 'C': 0, 'D': 0, 'F': 0}
                for mark in all_marks:
                    if mark >= 80:
                        grade_distribution['A'] += 1
                    elif mark >= 70:
                        grade_distribution['B'] += 1
                    elif mark >= 60:
                        grade_distribution['C'] += 1
                    elif mark >= 50:
                        grade_distribution['D'] += 1
                    else:
                        grade_distribution['F'] += 1
                overall_stats['grade_distribution'] = grade_distribution

            # Calculate performance summary with rankings for each exam
            performance_summary = []
            for exam_name, exam_data in exams_data.items():
                exam_id = exam_data['exam_id']
                total_marks = exam_data['total_marks']
                year = exam_data['date'][:4] if exam_data['date'] else 'N/A'
                
                # Get stream position (rank within the student's stream for this exam)
                stream_position = 'N/A'
                if stream:
                    # Get all students in same grade and stream with their totals
                    web_cursor.execute("""
                        SELECT s.id, SUM(r.marks) as total_marks
                        FROM students s
                        JOIN results r ON s.id = r.student_id
                        WHERE s.grade = ? AND s.stream = ? AND r.exam_id = ?
                        GROUP BY s.id
                        ORDER BY total_marks DESC
                    """, (grade, stream, exam_id))
                    stream_rankings = web_cursor.fetchall()
                    stream_position = 1
                    for idx, (sid, _) in enumerate(stream_rankings):
                        if sid == student_id:
                            stream_position = idx + 1
                            break
                
                # Get overall position (rank within the grade for this exam)
                web_cursor.execute("""
                    SELECT s.id, SUM(r.marks) as total_marks
                    FROM students s
                    JOIN results r ON s.id = r.student_id
                    WHERE s.grade = ? AND r.exam_id = ?
                    GROUP BY s.id
                    ORDER BY total_marks DESC
                """, (grade, exam_id))
                overall_rankings = web_cursor.fetchall()
                overall_position = 1
                for idx, (sid, _) in enumerate(overall_rankings):
                    if sid == student_id:
                        overall_position = idx + 1
                        break
                
                performance_summary.append({
                    'exam': exam_name,
                    'total_marks': total_marks,
                    'stream_position': stream_position,
                    'overall_position': overall_position,
                    'year': year
                })

            return {
                'student_info': {
                    'name': student_name,
                    'admission_number': admission_number,
                    'grade': grade,
                    'stream': stream,
                    'level': level
                },
                'exams_data': exams_data,
                'subject_stats': subject_stats,
                'overall_stats': overall_stats,
                'performance_summary': performance_summary,
                'total_results': len(results)
            }

        except Exception as e:
            print(f"Error generating student report: {e}")
            return None

    @web_app.route('/export_results')
    def export_results():
        if 'username' not in session:
            return redirect(url_for('login'))

        web_cursor.execute("""
            SELECT s.student_name, s.admission_number, sub.name AS subject, e.name AS exam, r.marks
            FROM results r
            JOIN students s ON r.student_id = s.id
            JOIN subjects sub ON r.subject_id = sub.id
            JOIN exams e ON r.exam_id = e.id
            ORDER BY s.student_name, e.created_at DESC
        """)
        rows = web_cursor.fetchall()

        output = io.StringIO()
        writer = csv.writer(output)
        writer.writerow(["Student", "Admission No", "Subject", "Exam", "Marks"])
        for row in rows:
            writer.writerow(row)

        response = web_app.make_response(output.getvalue())
        response.headers['Content-Disposition'] = 'attachment; filename=online_results.csv'
        response.mimetype = 'text/csv'
        return response

