    @web_app.route('/api/qr_code_image')
    def api_qr_code_image():
        """Generate and return a QR code image as PNG."""
        if not QR_AVAILABLE:
            return "QR Code not available", 404
        
        try:
            # Generate QR code pointing to the check results page
            results_url = request.host_url.rstrip('/') + '/check_results'
            qr = qrcode.QRCode(
                version=1,
                error_correction=qrcode.constants.ERROR_CORRECT_L,
                box_size=10,
                border=4,
            )
            qr.add_data(results_url)
            qr.make(fit=True)
            
            img = qr.make_image(fill_color="black", back_color="white")
            
            # Convert to PNG and return
            img_buffer = BytesIO()
            img.save(img_buffer, format='PNG')
            img_buffer.seek(0)
            
            return send_file(img_buffer, mimetype='image/png')
        except Exception as e:
            print(f"Error generating QR code: {e}")
            return f"Error: {str(e)}", 500

    @web_app.route('/qr_code')
    def qr_code():
        """Generate a QR code image for accessing the results page."""
        if not QR_AVAILABLE:
            return "QR Code not available - qrcode library not installed", 404
        
        try:
            # Get the server's IP or hostname for the QR code
            # The QR code should point to the public results checking page
            server_url = request.host_url.rstrip('/') + '/check_results'
            qr_image = generate_qr_code_image(server_url)
            
            if qr_image:
                # Return the image as base64 embed for direct use in HTML
                return qr_image.replace('data:image/png;base64,', ''), 200, {'Content-Type': 'image/png'}
            else:
                return "Failed to generate QR code", 500
        except Exception as e:
            print(f"Error in QR code route: {e}")
            return f"Error generating QR code: {str(e)}", 500

