# ================== DASHBOARD ================== #

def refresh_stats():
    # Totals
    cursor.execute("SELECT COUNT(*) FROM students")
    total_students = cursor.fetchone()[0]

    cursor.execute("SELECT COUNT(*) FROM exams")
    total_exams = cursor.fetchone()[0]

    cursor.execute("SELECT COUNT(*) FROM subjects")
    total_subjects = cursor.fetchone()[0]

    cursor.execute("SELECT COUNT(DISTINCT grade) FROM students")
    total_classes = cursor.fetchone()[0]

    # Header (centered, fancy)
    header_container = tk.Frame(main_frame, bg=BG_PRIMARY)
    header_container.pack(fill="x", pady=(12, 6))

    banner = tk.Frame(header_container, bg=ACCENT_BLUE, bd=0)
    banner.pack(padx=180, fill="x")

    title = tk.Label(banner, text="EDUSMART SOLUTIONS",
                     font=("Helvetica", 28, "bold"),
                     bg=ACCENT_BLUE, fg=TEXT_WHITE)
    title.pack(pady=(12, 4))

    motto = tk.Label(banner, text='"Knowledge is Power"',
                     font=("Arial", 12, "italic"),
                     bg=ACCENT_BLUE, fg=TEXT_WHITE)
    motto.pack(pady=(0, 12))

    # Greeting on banner right
    now = datetime.datetime.now()
    hour = now.hour
    if hour < 12:
        greet = "Good morning"
    elif hour < 18:
        greet = "Good afternoon"
    else:
        greet = "Good evening"

    greet_label = tk.Label(banner, text=f"{greet}!",
                           font=("Arial", 12, "bold"),
                           bg=ACCENT_BLUE, fg=TEXT_WHITE)
    greet_label.place(relx=0.86, rely=0.12, anchor="ne")

    clock_label = tk.Label(banner, text=now.strftime("%H:%M:%S"), font=("Courier", 12), bg=ACCENT_BLUE, fg=TEXT_WHITE)
    clock_label.place(relx=0.98, rely=0.12, anchor="ne")

    def _update_clock():
        try:
            clock_label.config(text=datetime.datetime.now().strftime("%H:%M:%S"))
            clock_label.after(1000, _update_clock)
        except tk.TclError:
            pass

    _update_clock()

    # Stat cards
    stats_container = tk.Frame(main_frame, bg=BG_PRIMARY)
    stats_container.pack(pady=(10, 8))

    card_style = {
        "bg": TEXT_WHITE,
        "bd": 1,
        "relief": "solid",
        "padx": 12,
        "pady": 10,
    }

    def make_card(parent, label_text, value_text, accent=ACCENT_GREEN, icon=None, w=260, h=140):
        card = tk.Frame(parent, bg=accent, bd=0)
        card.configure(width=w, height=h)
        card.pack_propagate(False)

        icon_label = None
        if icon:
            icon_label = tk.Label(card, text=icon, font=("Segoe UI Emoji", 22), bg=accent, fg=TEXT_WHITE)
            icon_label.pack(pady=(10, 0))

        val = tk.Label(card, text=value_text, font=("Helvetica", 20, "bold"), bg=accent, fg=TEXT_WHITE)
        val.pack(padx=8, pady=(8, 4))

        lbl = tk.Label(card, text=label_text, font=("Arial", 11, "bold"), bg=accent, fg=TEXT_WHITE)
        lbl.pack(padx=8, pady=(0, 10))

        # Hover effect: lighten background
        orig_bg = accent
        hover_bg = lighten_color(accent, 0.18)

        def on_enter(e):
            card.config(bg=hover_bg)
            if icon_label:
                icon_label.config(bg=hover_bg)
            val.config(bg=hover_bg)
            lbl.config(bg=hover_bg)

        def on_leave(e):
            card.config(bg=orig_bg)
            if icon_label:
                icon_label.config(bg=orig_bg)
            val.config(bg=orig_bg)
            lbl.config(bg=orig_bg)

        card.bind("<Enter>", on_enter)
        card.bind("<Leave>", on_leave)
        # ensure labels also respond
        for wdg in (val, lbl, icon_label):
            if wdg:
                wdg.bind("<Enter>", on_enter)
                wdg.bind("<Leave>", on_leave)

        return card

    card1 = make_card(stats_container, "Total Students", str(total_students), ACCENT_BLUE, icon="👥")
    card2 = make_card(stats_container, "Total Exams", str(total_exams), ACCENT_PURPLE, icon="📝")
    card3 = make_card(stats_container, "Total Subjects", str(total_subjects), ACCENT_ORANGE, icon="📚")
    card4 = make_card(stats_container, "Total Classes", str(total_classes), ACCENT_GREEN, icon="🏫")

    card1.pack(side="left", padx=12)
    card2.pack(side="left", padx=12)
    card3.pack(side="left", padx=12)
    card4.pack(side="left", padx=12)

    # Search box (students) to the right of the cards
    search_frame = tk.Frame(stats_container, bg=BG_PRIMARY)
    search_frame.pack(side="right", padx=(24, 0), anchor="e")

    search_var = tk.StringVar()
    search_entry = tk.Entry(search_frame, textvariable=search_var, width=20, font=("Arial", 12))
    search_entry.pack(side="left", padx=(0, 8))

    # Search button
    search_btn = tk.Button(search_frame, text="🔍 Search", bg=ACCENT_BLUE, fg=TEXT_WHITE,
                          font=("Arial", 10, "bold"), padx=12, pady=4, cursor="hand2",
                          command=lambda: perform_search())
    search_btn.pack(side="left")

    # Bind Enter key to search
    search_entry.bind("<Return>", lambda e: perform_search())

    # Results area below stats cards
    results_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    results_frame.pack(fill="x", padx=20, pady=(10, 0))

    # Results header (initially hidden)
    results_header = tk.Frame(results_frame, bg=BG_PRIMARY)
    results_label = tk.Label(results_header, text="", font=("Arial", 12, "bold"), bg=BG_PRIMARY, fg=ACCENT_BLUE)
    results_label.pack(side="left")

    # Clear search button (initially hidden)
    clear_btn = tk.Button(results_header, text="❌ Clear", bg=ACCENT_RED, fg=TEXT_WHITE,
                         font=("Arial", 10), padx=8, pady=2, command=lambda: clear_search())

    # Results container (scrollable)
    results_container = tk.Frame(results_frame, bg=BG_PRIMARY)

    # Store references for search functionality
    search_refs = {
        'results_frame': results_frame,
        'results_header': results_header,
        'results_label': results_label,
        'clear_btn': clear_btn,
        'results_container': results_container,
        'students_data': []
    }

    # Store references for popup search
    search_popup_ref = {
        'popup': None,
        'lb': None,
        'header_label': None,
        'action_frame': None,
        'students_data': []
    }

    def clear_search():
        """Clear search results and restore original student list"""
        search_var.set("")
        # Hide popup if open
        if search_popup_ref['popup'] is not None and search_popup_ref['popup'].winfo_exists():
            search_popup_ref['popup'].destroy()
            search_popup_ref['popup'] = None

    def perform_search():
        """Search for students when button is clicked or Enter is pressed"""
        q = search_var.get().strip()

        # If search box is empty, close popup
        if not q:
            if search_popup_ref['popup'] is not None and search_popup_ref['popup'].winfo_exists():
                search_popup_ref['popup'].destroy()
                search_popup_ref['popup'] = None
            return
        
        # Create popup if it doesn't exist
        if search_popup_ref['popup'] is None or not search_popup_ref['popup'].winfo_exists():
            popup = tk.Toplevel(root)
            popup.title("Search Results")
            popup.geometry("550x500")
            popup.transient(root)
            # Don't use grab_set() - this was hiding the table when typing
            popup.configure(bg=BG_PRIMARY)
            
            # Header
            header_label = tk.Label(popup, text="", font=("Arial", 12, "bold"), bg=BG_PRIMARY)
            header_label.pack(anchor="w", padx=10, pady=10)
            
            # Listbox with results
            lb_frame = tk.Frame(popup, bg=BG_PRIMARY)
            lb_frame.pack(fill="both", expand=True, padx=10, pady=(0, 10))
            
            lb = tk.Listbox(lb_frame, font=("Arial", 11), bg=TEXT_WHITE, selectmode="single", highlightthickness=0)
            lb.pack(side="left", fill="both", expand=True)
            
            scrollbar = tk.Scrollbar(lb_frame, orient="vertical", command=lb.yview)
            scrollbar.pack(side="right", fill="y")
            lb.config(yscroll=scrollbar.set)
            
            # Action buttons frame
            action_frame = tk.Frame(popup, bg=BG_PRIMARY)
            action_frame.pack(fill="x", padx=10, pady=10)
            
            search_popup_ref['popup'] = popup
            search_popup_ref['lb'] = lb
            search_popup_ref['header_label'] = header_label
            search_popup_ref['action_frame'] = action_frame
        
        # Bring popup to front
        popup = search_popup_ref['popup']
        if popup.winfo_exists():
            popup.lift()
            popup.focus()
        
        # Query database - search by name, admission number, or level
        cursor.execute("""
            SELECT id, student_name, admission_number, level, grade, stream 
            FROM students 
            WHERE student_name LIKE ? OR admission_number LIKE ? OR grade LIKE ?
            ORDER BY student_name
        """, (f"%{q}%", f"%{q}%", f"%{q}%"))
        rows = cursor.fetchall()
        
        # Clear and update listbox
        lb = search_popup_ref['lb']
        lb.delete(0, tk.END)
        
        # Store student data for later access
        students_data = []
        for r in rows:
            student_id, name, adm, level, grade, stream = r
            students_data.append({
                'id': student_id,
                'name': name,
                'admission': adm,
                'level': level,
                'grade': grade,
                'stream': stream
            })
            stream_str = f" {stream}" if stream else ""
            display_text = f"{name} — Adm: {adm} — {level} Grade {grade}{stream_str}"
            lb.insert("end", display_text)
        
        search_popup_ref['students_data'] = students_data
        
        # Update header
        search_popup_ref['header_label'].config(text=f"Found {len(rows)} student(s)")
        
        # Clear old buttons and add new ones
        for widget in search_popup_ref['action_frame'].winfo_children():
            widget.destroy()
        
        # Function to show options for selected student
        def show_student_options():
            selection = lb.curselection()
            if not selection:
                messagebox.showwarning("Selection", "Please select a student")
                return
            
            idx = selection[0]
            student = students_data[idx]
            
            # Create options dialog - don't grab focus from search popup
            options_popup = tk.Toplevel(root)
            options_popup.title(f"Student Options - {student['name']}")
            options_popup.geometry("400x350")
            options_popup.transient(root)
            # Don't use grab_set() - this allows search popup to remain visible and functional
            options_popup.configure(bg=BG_PRIMARY)
            
            # Title with student info
            tk.Label(options_popup, text=f"📚 {student['name']}", font=("Arial", 14, "bold"), bg=BG_PRIMARY, fg=ACCENT_BLUE).pack(pady=10)
            tk.Label(options_popup, text=f"Admission: {student['admission']} | {student['level']} Grade {student['grade']}", font=("Arial", 10), bg=BG_PRIMARY, fg="#666666").pack(pady=(0, 20))
            
            # Divider
            ttk.Separator(options_popup, orient="horizontal").pack(fill="x", padx=20, pady=(0, 15))
            
            # Option buttons
            tk.Label(options_popup, text="What would you like to view?", font=("Arial", 11, "bold"), bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=(0, 10))
            
            btn_frame = tk.Frame(options_popup, bg=BG_PRIMARY)
            btn_frame.pack(fill="both", expand=True, padx=20, pady=10)
            
            def view_student_details_from_search():
                show_student_details_popup(student)
                options_popup.destroy()
            
            def view_performance_from_search():
                show_performance_summary_popup(student)
                options_popup.destroy()
            
            def view_trends_from_search():
                show_student_performance_trends_popup(student)
                options_popup.destroy()
            
            # Option buttons
            tk.Button(btn_frame, text="📊 Performance Summary", bg=ACCENT_PURPLE, fg=TEXT_WHITE, 
                     font=("Arial", 10, "bold"), padx=15, pady=12, width=30,
                     command=view_performance_from_search).pack(fill="x", pady=8)
            
            tk.Button(btn_frame, text="📈 Performance Trends", bg=ACCENT_GREEN, fg=TEXT_WHITE, 
                     font=("Arial", 10, "bold"), padx=15, pady=12, width=30,
                     command=view_trends_from_search).pack(fill="x", pady=8)
            
            tk.Button(btn_frame, text="👤 Student Details", bg=ACCENT_BLUE, fg=TEXT_WHITE, 
                     font=("Arial", 10, "bold"), padx=15, pady=12, width=30,
                     command=view_student_details_from_search).pack(fill="x", pady=8)
        
        # If only one result, automatically show the student options
        if len(rows) == 1:
            student = students_data[0]
            lb.selection_set(0)
            show_student_options()
            return
        
        if len(rows) > 0:
            # View button - clickable
            tk.Button(search_popup_ref['action_frame'], text="👉 View Options", bg=ACCENT_GREEN, fg=TEXT_WHITE, 
                     font=("Arial", 10, "bold"), padx=20, pady=8, command=show_student_options).pack(side="left", padx=5)
            tk.Button(search_popup_ref['action_frame'], text="❌ Close", bg=ACCENT_RED, fg=TEXT_WHITE, 
                     font=("Arial", 10, "bold"), padx=20, pady=8, command=lambda: search_popup_ref['popup'].destroy()).pack(side="left", padx=5)
            
            # Add double-click support on listbox
            def on_double_click(event):
                show_student_options()
            
            lb.bind("<Double-Button-1>", on_double_click)
            
            # Select first item by default
            if len(rows) > 0:
                lb.selection_set(0)
        else:
            tk.Label(search_popup_ref['action_frame'], text="❌ No results found", font=("Arial", 10, "italic"), bg=BG_PRIMARY, fg="#999999").pack(pady=5)
            tk.Button(search_popup_ref['action_frame'], text="Close", bg=ACCENT_RED, fg=TEXT_WHITE, 
                     font=("Arial", 10, "bold"), padx=20, pady=8, command=lambda: search_popup_ref['popup'].destroy()).pack(side="left", padx=5)

    def show_student_details_popup(student):
        """Show student details in a popup with improved UI"""
        details_popup = tk.Toplevel(root)
        details_popup.title(f"Student Details - {student['name']}")
        details_popup.geometry("600x700")
        details_popup.transient(root)
        details_popup.grab_set()
        details_popup.configure(bg=BG_PRIMARY)

        # Header with gradient effect
        header_frame = tk.Frame(details_popup, bg=ACCENT_BLUE)
        header_frame.pack(fill="x", padx=0, pady=0)
        
        tk.Label(header_frame, text=f"📋 Student Information", font=("Arial", 16, "bold"), bg=ACCENT_BLUE, fg=TEXT_WHITE).pack(pady=(15, 5), padx=20, anchor="w")
        tk.Label(header_frame, text=f"{student['name']}", font=("Arial", 13), bg=ACCENT_BLUE, fg=lighten_color(TEXT_WHITE, 0.3)).pack(pady=(0, 15), padx=20, anchor="w")

        # Scrollable content area
        canvas = tk.Canvas(details_popup, bg=BG_PRIMARY, highlightthickness=0)
        scrollbar = ttk.Scrollbar(details_popup, orient="vertical", command=canvas.yview)
        scrollable_frame = tk.Frame(canvas, bg=BG_PRIMARY)
        
        scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )
        
        canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)
        
        # Get student details
        cursor.execute("SELECT parent_name, parent_phone, parent_id, student_details, stream, assessment_number FROM students WHERE id=?", (student['id'],))
        details = cursor.fetchone()

        if details:
            parent_name, parent_phone, parent_id, student_details, stream, assessment_number = details
            
            # Try to get registration date from first exam result (when student was first active)
            cursor.execute("""
                SELECT MIN(e.created_at) FROM results r
                JOIN exams e ON r.exam_id = e.id
                WHERE r.student_id = ?
            """, (student['id'],))
            first_exam_date = cursor.fetchone()[0]
            
            # Format registration date
            if first_exam_date:
                try:
                    reg_date = datetime.datetime.fromisoformat(first_exam_date).strftime("%B %Y")
                except:
                    reg_date = "Date tracked"
            else:
                reg_date = "Recently registered"

            # ===== ACADEMIC INFO CARD =====
            academic_card = tk.Frame(scrollable_frame, bg=TEXT_WHITE, relief="flat", bd=0)
