                # Color code based on value
                if label == "Assessment Number" and not assessment_number:
                    text_color = "#FF9800"  # Orange for not registered
                elif label == "Registration Date" and "Recently" in value:
                    text_color = "#999999"  # Grey for no exam history
                else:
                    text_color = ACCENT_BLUE
                
                tk.Label(detail_row, text=value, font=("Arial", 10), bg=TEXT_WHITE, fg=text_color).pack(side="left", fill="x", expand=True)
            
