    def show_performance_summary_popup(student):
        """Show student performance summary in a popup as a table with improved UI"""
        summary_popup = tk.Toplevel(root)
        summary_popup.title(f"Performance Summary - {student['name']}")
        summary_popup.geometry("950x600")
        summary_popup.transient(root)
        summary_popup.grab_set()
        summary_popup.configure(bg=BG_PRIMARY)

        # Header with gradient effect
        header_frame = tk.Frame(summary_popup, bg=ACCENT_PURPLE)
        header_frame.pack(fill="x", padx=0, pady=0)
        
        tk.Label(header_frame, text=f"📊 Performance Summary", font=("Arial", 16, "bold"), bg=ACCENT_PURPLE, fg=TEXT_WHITE).pack(pady=(15, 5), padx=20, anchor="w")
        tk.Label(header_frame, text=f"{student['name']} • {student['level']} Grade {student['grade']} • Adm: {student['admission']}", font=("Arial", 11), bg=ACCENT_PURPLE, fg=lighten_color(TEXT_WHITE, 0.3)).pack(pady=(0, 15), padx=20, anchor="w")

        # Content frame with table
        table_frame = tk.Frame(summary_popup, bg=BG_PRIMARY)
        table_frame.pack(fill="both", expand=True, padx=12, pady=12)

        # Get all exam results for this student
        try:
            cursor.execute("""
                SELECT DISTINCT e.id, e.name, e.exam_id
                FROM results r
                JOIN exams e ON r.exam_id = e.id
                WHERE r.student_id = ?
                ORDER BY e.id DESC
            """, (student['id'],))
            
            exam_list = cursor.fetchall()
        except Exception as e:
            print(f"Error fetching exams: {e}")
            exam_list = []

        if exam_list:
            # Configure ttk style for proper header visibility and alignment
            style = ttk.Style()
            style.theme_use('clam')  # Use clam theme for better customization
            
            # Configure Treeview heading style
            style.configure('Treeview.Heading', 
                          font=("Arial", 10, "bold"),
                          background=ACCENT_PURPLE,
                          foreground=TEXT_WHITE,
                          padding=8,
                          relief="flat")
            style.map('Treeview.Heading',
                     background=[('active', ACCENT_PURPLE)])
            
            # Configure Treeview row style
            style.configure('Treeview',
                          font=("Arial", 9),
                          rowheight=32,
                          padding=5)
            style.configure('Treeview.Treerow',
                          padding=8)
            
            # Create Treeview with headers visible
            columns = ('Exam', 'Total Marks', 'Stream Rank', 'Year', 'Overall Rank')
            tree = ttk.Treeview(table_frame, columns=columns, height=12, show='tree headings',
                               style="Treeview")
            
            # Configure column headings and widths
            tree.heading('#0', text='')
            tree.heading('Exam', text='Exam')
            tree.heading('Total Marks', text='Total Marks')
            tree.heading('Stream Rank', text='Stream Rank')
            tree.heading('Year', text='Year')
            tree.heading('Overall Rank', text='Overall Rank')
            
            tree.column('#0', width=0, stretch=False)
            tree.column('Exam', width=200, anchor='w', stretch=False)
            tree.column('Total Marks', width=120, anchor='center', stretch=False)
            tree.column('Stream Rank', width=120, anchor='center', stretch=False)
            tree.column('Year', width=100, anchor='center', stretch=False)
            tree.column('Overall Rank', width=120, anchor='center', stretch=False)
            
            # Add rows
            for idx, exam_info in enumerate(exam_list):
                exam_internal_id, exam_name, exam_code = exam_info
                
                # Get total marks for this exam and number of subjects
                cursor.execute("""
                    SELECT SUM(r.marks), COUNT(*) as num_subjects
                    FROM results r
                    WHERE r.student_id = ? AND r.exam_id = ?
                """, (student['id'], exam_internal_id))
                
                marks_result = cursor.fetchone()
                total_marks = int(marks_result[0]) if marks_result and marks_result[0] is not None else 0
                num_subjects = marks_result[1] if marks_result and marks_result[1] is not None else 0
                
                # Calculate maximum possible marks (assuming 100 marks per subject)
                max_possible_marks = num_subjects * 100 if num_subjects > 0 else 0
                
                # Format total marks display as "245/500" (marks out of max possible)
                if max_possible_marks > 0:
                    marks_display = f"{total_marks}/{max_possible_marks}"
                else:
                    marks_display = f"{total_marks}/0"
                
                # Get submitted/exam date for year extraction
                cursor.execute("""
                    SELECT MAX(r.submitted_at), e.start_date
                    FROM results r
                    JOIN exams e ON r.exam_id = e.id
                    WHERE r.student_id = ? AND r.exam_id = ?
                """, (student['id'], exam_internal_id))
                
                date_result = cursor.fetchone()
                year = "N/A"
                if date_result:
                    submitted_date = date_result[0]
                    exam_date = date_result[1]
                    
                    if submitted_date:
                        import datetime
                        try:
                            date_obj = datetime.datetime.strptime(submitted_date, "%Y-%m-%d %H:%M:%S")
                            year = date_obj.strftime("%Y")
                        except:
                            year = "N/A"
                    elif exam_date and isinstance(exam_date, str):
                        year = exam_date[:4] if len(exam_date) >= 4 else "N/A"
                
                # Get stream rank - for students in same grade and stream
                student_stream = student.get('stream', '')
                stream_rank = "N/A"
                stream_rank_display = "N/A"
                
                if student_stream:
                    # Get all students in the same grade and stream with their totals for this exam
                    cursor.execute("""
                        SELECT s.id, COALESCE(SUM(r.marks), 0) as student_total
                        FROM students s
                        LEFT JOIN results r ON s.id = r.student_id AND r.exam_id = ?
                        WHERE s.grade = ? AND s.stream = ?
                        GROUP BY s.id
                        ORDER BY student_total DESC
                    """, (exam_internal_id, student['grade'], student_stream))
                    
                    stream_rankings = cursor.fetchall()
                    total_stream_students = len(stream_rankings)
                    for rank_idx, (sid, _) in enumerate(stream_rankings):
                        if sid == student['id']:
                            stream_rank = rank_idx + 1
                            stream_rank_display = f"{stream_rank}/{total_stream_students}"
                            break
                
                # Get overall rank - for all students in the same grade
                cursor.execute("""
                    SELECT s.id, COALESCE(SUM(r.marks), 0) as student_total
                    FROM students s
                    LEFT JOIN results r ON s.id = r.student_id AND r.exam_id = ?
                    WHERE s.grade = ?
                    GROUP BY s.id
                    ORDER BY student_total DESC
                """, (exam_internal_id, student['grade']))
                
                overall_rankings = cursor.fetchall()
                overall_rank = "N/A"
                overall_rank_display = "N/A"
                total_grade_students = len(overall_rankings)
                for rank_idx, (sid, _) in enumerate(overall_rankings):
                    if sid == student['id']:
                        overall_rank = rank_idx + 1
                        overall_rank_display = f"{overall_rank}/{total_grade_students}"
                        break
                
                # Color based on performance
                if total_marks >= 50:
                    tag = 'good'
                elif total_marks >= 40:
                    tag = 'fair'
                else:
                    tag = 'poor'
                
                tree.insert('', 'end', values=(exam_name, marks_display, stream_rank_display, year, overall_rank_display), tags=(tag,))
            
            # Configure tag colors
            tree.tag_configure('good', background=lighten_color(ACCENT_GREEN, 0.3))
            tree.tag_configure('fair', background=lighten_color(ACCENT_ORANGE, 0.3))
            tree.tag_configure('poor', background=lighten_color(ACCENT_ORANGE, 0.4))
            
            # Scrollbar
            scrollbar = ttk.Scrollbar(table_frame, orient='vertical', command=tree.yview)
            tree.configure(yscroll=scrollbar.set)
            scrollbar.pack(side='right', fill='y')
            tree.pack(fill="both", expand=True)

        else:
            no_data_frame = tk.Frame(table_frame, bg=lighten_color(ACCENT_ORANGE, 0.2))
            no_data_frame.pack(fill="both", expand=True, padx=12, pady=20)
            
            tk.Label(no_data_frame, text="📭 No exam results yet", font=("Arial", 12, "bold"),
                   bg=lighten_color(ACCENT_ORANGE, 0.2), fg=ACCENT_ORANGE).pack(pady=(10, 5))
            tk.Label(no_data_frame, text="This student hasn't taken any exams yet.",
                   font=("Arial", 10), bg=lighten_color(ACCENT_ORANGE, 0.2), fg=TEXT_DARK).pack(pady=(0, 10))

        # Footer with close button
        footer_frame = tk.Frame(summary_popup, bg=BG_PRIMARY)
        footer_frame.pack(fill="x", padx=12, pady=12)
        
        tk.Button(footer_frame, text="✓ Close", bg=ACCENT_PURPLE, fg=TEXT_WHITE,
                font=("Arial", 11, "bold"), padx=30, pady=10,
                command=summary_popup.destroy).pack(side="right")

    def show_student_performance_trends_popup(student):
        """Show student performance trends graph in a popup with improved UI"""
        trends_popup = tk.Toplevel(root)
        trends_popup.title(f"Performance Trends - {student['name']}")
        trends_popup.geometry("750x650")
        trends_popup.transient(root)
        trends_popup.grab_set()
        trends_popup.configure(bg=BG_PRIMARY)

        # Header with gradient effect
        header_frame = tk.Frame(trends_popup, bg=ACCENT_GREEN)
        header_frame.pack(fill="x", padx=0, pady=0)
        
        tk.Label(header_frame, text=f"📈 Performance Trends", font=("Arial", 16, "bold"), bg=ACCENT_GREEN, fg=TEXT_WHITE).pack(pady=(15, 5), padx=20, anchor="w")
        tk.Label(header_frame, text=f"{student['name']} • {student['level']} Grade {student['grade']} • Adm: {student['admission']}", font=("Arial", 11), bg=ACCENT_GREEN, fg=lighten_color(TEXT_WHITE, 0.3)).pack(pady=(0, 15), padx=20, anchor="w")

        # Content area for the graph
        content_frame = tk.Frame(trends_popup, bg=BG_PRIMARY)
        content_frame.pack(fill="both", expand=True, padx=15, pady=15)

        try:
            # Get all exam results for this student across all exams
            cursor.execute("""
                SELECT DISTINCT e.id, e.name, e.exam_id, AVG(r.marks) as avg_marks
                FROM results r
                JOIN exams e ON r.exam_id = e.id
                WHERE r.student_id = ? AND r.marks IS NOT NULL
                GROUP BY e.id
                ORDER BY e.id ASC
            """, (student['id'],))

            exam_data = cursor.fetchall()

            if not exam_data or len(exam_data) == 0:
                tk.Label(content_frame, text="No trend data available - student has no exam results yet.",
                       font=("Arial", 11, "italic"), bg=BG_PRIMARY, fg="#999999").pack(pady=20)
            else:
                # Extract data for graph: exam[0]=id, exam[1]=name, exam[2]=exam_id, exam[3]=avg_marks
                exam_names = [f"{exam[1]}" for exam in exam_data]
                marks = [float(exam[3]) if exam[3] is not None else 0 for exam in exam_data]

                # Create matplotlib figure
                fig = plt.Figure(figsize=(7, 5), dpi=80)
                ax = fig.add_subplot(111)

                # Plot line graph
                ax.plot(range(len(exam_names)), marks, marker='o', linewidth=2, markersize=8, color=ACCENT_BLUE, label='Average Marks')
                
                # Add value labels on points
                for i, mark in enumerate(marks):
                    ax.text(i, mark + 2, f'{mark:.1f}', ha='center', va='bottom', fontsize=9, fontweight='bold')

                ax.set_xlabel('Exam', fontsize=10, fontweight='bold')
                ax.set_ylabel('Average Marks', fontsize=10, fontweight='bold')
                ax.set_title(f"Trend Analysis: {student['name']}", fontsize=12, fontweight='bold')
                ax.set_xticks(range(len(exam_names)))
                ax.set_xticklabels(exam_names, fontsize=9)
                ax.grid(True, linestyle='--', alpha=0.3)
                ax.set_ylim(0, 105)
                ax.legend(loc='upper left')

                fig.tight_layout()

                # Embed in tkinter
                canvas = FigureCanvasTkAgg(fig, master=content_frame)
                canvas.draw()
                canvas.get_tk_widget().pack(fill="both", expand=True)

        except Exception as e:
            tk.Label(content_frame, text=f"Error loading trends: {str(e)}",
                   font=("Arial", 11, "italic"), bg=BG_PRIMARY, fg="red").pack(pady=20)
            print(f"Trends error: {e}")

        # Footer with close button
        btn_frame = tk.Frame(trends_popup, bg=BG_PRIMARY)
        btn_frame.pack(fill="x", padx=15, pady=12)
        tk.Button(btn_frame, text="✓ Close", bg=ACCENT_GREEN, fg=TEXT_WHITE,
                font=("Arial", 11, "bold"), padx=30, pady=10,
                command=trends_popup.destroy).pack(side="right")

    # Quick action buttons below cards
    quick_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    quick_frame.pack(fill="x", padx=24, pady=(10, 6))

    tk.Button(quick_frame, text="➕ Add Student", bg=ACCENT_GREEN, fg=TEXT_WHITE, padx=12, pady=6, bd=0, command=show_students).pack(side="left", padx=8)
    tk.Button(quick_frame, text="📝 Register Exam", bg=ACCENT_BLUE, fg=TEXT_WHITE, padx=12, pady=6, bd=0, command=show_exams).pack(side="left", padx=8)
    tk.Button(quick_frame, text="📊 Quick Reports", bg=ACCENT_PURPLE, fg=TEXT_WHITE, padx=12, pady=6, bd=0, command=show_reports).pack(side="left", padx=8)

    # Charts area (two charts: KPSEA marks and KJSEA points)
    charts_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    charts_frame.pack(fill="both", expand=True, padx=20, pady=(12, 20))

    # Left chart - KPSEA
    left_chart = tk.Frame(charts_frame, bg=BG_PRIMARY)
    left_chart.pack(side="left", fill="both", expand=True, padx=5)

    # Middle chart - KJSEA
    middle_chart = tk.Frame(charts_frame, bg=BG_PRIMARY)
    middle_chart.pack(side="left", fill="both", expand=True, padx=5)

    def plot_kpsea_marks_distribution():
        """Plot KPSEA students distribution by average marks across all exams"""
        # Fetch all KPSEA students and their average marks across exams
        cursor.execute("""
            SELECT s.id, s.student_name, AVG(r.marks) as avg_mark
            FROM students s
            LEFT JOIN results r ON s.id = r.student_id
            WHERE s.level = 'KPSEA'
            GROUP BY s.id
        """)
        students = cursor.fetchall()
        
        # Calculate marks distribution for each student
        mark_counts = {
            'Exceeding\n(75-100)': 0,
            'Meeting\n(41-74)': 0,
            'Approaching\n(21-40)': 0,
            'Below\n(0-20)': 0
        }
        
        for student_id, name, avg_mark in students:
            if avg_mark is not None:
                avg_mark = float(avg_mark)
                if avg_mark >= 75:
                    mark_counts['Exceeding\n(75-100)'] += 1
                elif avg_mark >= 41:
                    mark_counts['Meeting\n(41-74)'] += 1
                elif avg_mark >= 21:
                    mark_counts['Approaching\n(21-40)'] += 1
                else:
                    mark_counts['Below\n(0-20)'] += 1
        
        # Create bar chart
        fig = plt.Figure(figsize=(4, 3), dpi=80)
        ax = fig.add_subplot(111)
        
        labels = list(mark_counts.keys())
        counts = list(mark_counts.values())
        colors_list = [ACCENT_GREEN, ACCENT_BLUE, ACCENT_ORANGE, '#FF6B6B']
        
        ax.bar(labels, counts, color=colors_list)
        ax.set_title("KPSEA - Marks Distribution\n(Avg across all exams)")
        ax.set_xlabel("Mark Range")
        ax.set_ylabel("Total Students")
        ax.grid(axis='y', linestyle='--', alpha=0.3)
        
        fig.tight_layout()
        
        canvas = FigureCanvasTkAgg(fig, master=left_chart)
        canvas.draw()
        canvas.get_tk_widget().pack(fill="both", expand=True)


    def plot_kjsea_points_distribution():
        """Plot KJSEA students distribution by average points across all exams"""
        # Fetch all KJSEA students and their average marks across exams
        cursor.execute("""
            SELECT s.id, s.student_name, AVG(r.marks) as avg_mark
            FROM students s
            LEFT JOIN results r ON s.id = r.student_id
            WHERE s.level = 'KJSEA'
            GROUP BY s.id
        """)
        students = cursor.fetchall()
        
        # Calculate average points for each student
        point_counts = {'8': 0, '7': 0, '6': 0, '5': 0, '4': 0, '3': 0, '2': 0, '1': 0}
        point_labels = {
            '8': 'High (8)',
            '7': 'High (7)',
            '6': 'Semi-High (6)',
            '5': 'Average (5)',
            '4': 'Low-Avg (4)',
            '3': 'Low (3)',
            '2': 'Very Low (2)',
            '1': 'Critical (1)'
        }
        
        for student_id, name, avg_mark in students:
            if avg_mark is not None:
                # Get points based on average mark
                _, points = get_performance_level(avg_mark, "KJSEA")
                point_counts[points] = point_counts.get(points, 0) + 1
        
        # Create bar chart
        fig = plt.Figure(figsize=(4, 3), dpi=80)
        ax = fig.add_subplot(111)
        
        # Sort by point value descending for better visualization
        points_order = ['8', '7', '6', '5', '4', '3', '2', '1']
        labels = [point_labels[p] for p in points_order]
        counts = [point_counts[p] for p in points_order]
        colors_list = [ACCENT_GREEN, ACCENT_BLUE, ACCENT_PURPLE, ACCENT_ORANGE, '#FF6B6B', '#FFA500', '#DC143C', '#8B0000']
        
        ax.bar(labels, counts, color=colors_list)
        ax.set_title("KJSEA - Points Distribution\n(Avg across all exams)")
        ax.set_xlabel("Point Range")
        ax.set_ylabel("Total Students")
        ax.grid(axis='y', linestyle='--', alpha=0.3)
        
        # Use shorter labels and adjust layout
        ax.set_xticks(range(len(labels)))
        ax.set_xticklabels([l.replace(' ', '\n') for l in labels], fontsize=8)
        
        fig.tight_layout()
        
        canvas = FigureCanvasTkAgg(fig, master=middle_chart)
        canvas.draw()
        canvas.get_tk_widget().pack(fill="both", expand=True)

    def plot_streams_distribution():
        """Plot student distribution across registered streams as a pie chart"""
        # Fetch student count per stream
        cursor.execute("""
            SELECT s.name, COUNT(st.id) as student_count
            FROM students st
            JOIN streams s ON st.stream = s.name
            GROUP BY s.name
            ORDER BY student_count DESC
        """)
        stream_data = cursor.fetchall()
        
        if not stream_data:
            # No streams with students
            fig = plt.Figure(figsize=(4, 3), dpi=80)
            ax = fig.add_subplot(111)
            ax.text(0.5, 0.5, 'No students\nenrolled in streams', 
                   ha='center', va='center', fontsize=12, 
                   transform=ax.transAxes, color='#999999')
            ax.set_title("Stream Distribution")
            ax.axis('off')
        else:
            # Create pie chart
            fig = plt.Figure(figsize=(4, 3), dpi=80)
            ax = fig.add_subplot(111)
            
            streams = [row[0] for row in stream_data]
            counts = [row[1] for row in stream_data]
            
            # Color palette for streams
            colors = ['#FF6B6B', '#4ECDC4', '#45B7D1', '#96CEB4', '#FFEAA7', 
                     '#DDA0DD', '#98D8C8', '#F7DC6F', '#BB8FCE', '#85C1E9']
            
            # Use colors cyclically if more streams than colors
            stream_colors = colors * (len(streams) // len(colors) + 1)
            stream_colors = stream_colors[:len(streams)]
            
            # Create pie chart
            wedges, texts, autotexts = ax.pie(counts, labels=streams, autopct='%1.1f%%', 
                                             colors=stream_colors, startangle=90,
                                             pctdistance=0.85, labeldistance=1.1)
            
            # Style the chart
            ax.set_title("Student Distribution by Stream", fontsize=12, fontweight='bold')
            
            # Make percentage text more readable
            for autotext in autotexts:
                autotext.set_color('white')
                autotext.set_fontsize(9)
                autotext.set_fontweight('bold')
            
            # Add legend if too many streams
            if len(streams) > 5:
                ax.legend(wedges, streams, title="Streams", loc="center left", 
                         bbox_to_anchor=(1, 0, 0.5, 1), fontsize=8)
                # Remove labels from pie if legend is used
                for text in texts:
                    text.set_text('')
        
        fig.tight_layout()
        
        canvas = FigureCanvasTkAgg(fig, master=right_chart)
        canvas.draw()
        canvas.get_tk_widget().pack(fill="both", expand=True)

    plot_kpsea_marks_distribution()
    plot_kjsea_points_distribution()
    
    # Add system status footer
    footer_frame = tk.Frame(main_frame, bg=lighten_color(BG_PRIMARY, 0.08), relief="solid", bd=1)
    footer_frame.pack(fill="x", padx=20, pady=20)
    
    status_left = tk.Frame(footer_frame, bg=lighten_color(BG_PRIMARY, 0.08))
    status_left.pack(side="left", fill="both", expand=True, padx=15, pady=10)
    
    status_right = tk.Frame(footer_frame, bg=lighten_color(BG_PRIMARY, 0.08))
    status_right.pack(side="right", fill="both", expand=True, padx=15, pady=10)
    
    # Left side - System Info
    tk.Label(status_left, text="📋 System Status", font=("Arial", 10, "bold"), bg=lighten_color(BG_PRIMARY, 0.08), fg=ACCENT_BLUE).pack(anchor="w", pady=(0, 6))
    
    # Get additional stats
    cursor.execute("SELECT COUNT(DISTINCT grade) FROM students WHERE level='ALUMNI'")
    alumni_count = cursor.fetchone()[0]
    cursor.execute("SELECT COUNT(*) FROM results WHERE marks IS NOT NULL")
    marked_count = cursor.fetchone()[0]
    
    status_text = f"✓ {marked_count} exam marks recorded | 👥 {alumni_count} alumni tracked"
    tk.Label(status_left, text=status_text, font=("Arial", 9), bg=lighten_color(BG_PRIMARY, 0.08), fg=TEXT_DARK).pack(anchor="w")
    
    # Right side - Quick Actions
    tk.Label(status_right, text="⚡ Quick Actions", font=("Arial", 10, "bold"), bg=lighten_color(BG_PRIMARY, 0.08), fg=ACCENT_PURPLE).pack(anchor="w", pady=(0, 6))
    
    quick_btn_frame = tk.Frame(status_right, bg=lighten_color(BG_PRIMARY, 0.08))
    quick_btn_frame.pack(anchor="w", fill="x")
    
    tk.Button(quick_btn_frame, text="📝 New Exam", bg=ACCENT_BLUE, fg=TEXT_WHITE, command=lambda: show_register_exam(), font=("Arial", 8), padx=8, pady=3).pack(side="left", padx=(0, 5))
    tk.Button(quick_btn_frame, text="🎓 Add Student", bg=ACCENT_GREEN, fg=TEXT_WHITE, command=lambda: show_students(), font=("Arial", 8), padx=8, pady=3).pack(side="left", padx=5)
    tk.Button(quick_btn_frame, text="💾 Backup", bg=ACCENT_ORANGE, fg=TEXT_WHITE, command=lambda: show_data_management(), font=("Arial", 8), padx=8, pady=3).pack(side="left", padx=5)




