def show_subjects():
    clear_main()

    tk.Label(main_frame, text="📚 Subject Management",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=20)

    # Subject symbols mapping
    subject_symbols = {
        "Maths": "🔢",
        "English": "📖",
        "Kiswahili": "🗣️",
        "Agriculture": "🌾",
        "Social Studies": "🌍",
        "Creative Arts": "🎨",
        "C.R.E": "✝️",
        "Integrated Science": "🔬",
        "Pre-Technical Studies": "⚙️",
    }

    # Add new subject section
    tk.Label(main_frame, text="Add New Subject",
             font=("Arial", 12, "bold"),
             bg=BG_PRIMARY, fg=ACCENT_BLUE).pack(anchor="w", padx=20, pady=(10, 12))

    add_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    add_frame.pack(fill="x", padx=20, pady=(0, 20))

    entry = tk.Entry(add_frame, width=30, font=("Arial", 10))
    entry.pack(side="left", padx=(0, 8))
    
    # Bind Enter to add subject
    entry.bind("<Return>", lambda e: add_subject())

    level_var = tk.StringVar(value="KPSEA")
    level_combo = ttk.Combobox(add_frame, textvariable=level_var,
                 values=["KPSEA", "KJSEA"],
                 state="readonly", width=12)
    level_combo.pack(side="left", padx=(0, 8))

    grade_var = tk.StringVar(value="1")
    grade_label = tk.Label(add_frame, text="Grade:", bg=BG_PRIMARY)
    grade_label.pack(side="left", padx=(0, 4))
    grade_combo = ttk.Combobox(add_frame, textvariable=grade_var,
                 values=[str(i) for i in range(1, 7)],
                 state="readonly", width=6)
    grade_combo.pack(side="left", padx=(0, 8))

    LEVEL_GRADE_OPTIONS = {
        "KPSEA": [str(i) for i in range(1, 7)],
        "KJSEA": KJSEA_GRADES,
    }

    def on_level_change(event=None):
        selected = level_var.get()
        grade_label.config(state="normal")
        grade_combo.config(state="readonly")
        grade_combo.config(values=LEVEL_GRADE_OPTIONS[selected])
        if grade_var.get() not in LEVEL_GRADE_OPTIONS[selected]:
            grade_var.set(LEVEL_GRADE_OPTIONS[selected][0])

    level_combo.bind("<<ComboboxSelected>>", on_level_change)
    on_level_change()

    def add_subject():
        name = entry.get().strip()
        if not name:
            messagebox.showerror("Error", "Subject name is required")
            return
        
        # Validate subject name (letters, spaces, hyphens only)
        if len(name) > 50:
            messagebox.showerror("Error", "Subject name too long (max 50 characters)")
            return
        if any(char.isdigit() for char in name):
            messagebox.showerror("Error", "Subject name should not contain numbers")
            return
        
        selected_level = level_var.get()
        if selected_level == "KJSEA":
            normalized = ''.join(ch for ch in name.strip().lower() if ch.isalnum())
            if normalized in KJSEA_CANONICAL_NAMES:
                name = KJSEA_CANONICAL_NAMES[normalized]
        selected_grade = int(grade_var.get())

        cursor.execute(
            "SELECT s.id FROM subjects s JOIN subject_levels sl ON s.id=sl.subject_id WHERE s.name=? AND sl.level=? AND sl.grade=?",
            (name, selected_level, selected_grade)
        )
        if cursor.fetchone():
            messagebox.showwarning("Info", f"Subject '{name}' already exists in {selected_level} Grade {selected_grade}")
            return

        # use existing subject if possible
        cursor.execute("SELECT id FROM subjects WHERE name=?", (name,))
        row = cursor.fetchone()
        if row:
            subject_id = row[0]
        else:
            cursor.execute("INSERT INTO subjects(name) VALUES(?)", (name,))
            subject_id = cursor.lastrowid

        # ensure level and grade link
        cursor.execute(
            "SELECT 1 FROM subject_levels WHERE subject_id=? AND level=? AND grade IS ?",
            (subject_id, selected_level, selected_grade)
        )
        if not cursor.fetchone():
            cursor.execute(
                "INSERT INTO subject_levels(subject_id, level, grade) VALUES(?,?,?)",
                (subject_id, selected_level, selected_grade)
            )
        conn.commit()

        grade_text = f" Grade {selected_grade}" if selected_grade else ""
        messagebox.showinfo("Success", f"Subject '{name}' added to {selected_level}{grade_text}")
        entry.delete(0, tk.END)
        show_subjects()

    def delete_subject(subject_name, level, grade=None):
        grade_label = f" Grade {grade}" if grade is not None else ""
        if not messagebox.askyesno(
            "Confirm Delete",
            f"Delete subject '{subject_name}' from {level}{grade_label}? This will remove related marks or targets for affected students."
        ):
            return

        cursor.execute("SELECT id FROM subjects WHERE name=?", (subject_name,))
        row = cursor.fetchone()
        if not row:
            messagebox.showerror("Error", f"Subject '{subject_name}' not found")
            return
        subject_id = row[0]

        if grade is not None:
            cursor.execute(
                "DELETE FROM subject_levels WHERE subject_id=? AND level=? AND grade=?",
                (subject_id, level, grade)
            )
        else:
            cursor.execute("DELETE FROM subject_levels WHERE subject_id=? AND level=?", (subject_id, level))

        cursor.execute("SELECT COUNT(*) FROM subject_levels WHERE subject_id=?", (subject_id,))
        remaining = cursor.fetchone()[0]
        if remaining == 0:
            cursor.execute("DELETE FROM results WHERE subject_id=?", (subject_id,))
            cursor.execute("DELETE FROM candidate_targets WHERE subject_id=?", (subject_id,))
            cursor.execute("DELETE FROM subjects WHERE id=?", (subject_id,))
        else:
            if grade is not None:
                cursor.execute("SELECT id FROM students WHERE grade=?", (grade,))
                student_ids = [r[0] for r in cursor.fetchall()]
            else:
                if level == "KPSEA":
                    level_grades = [1, 2, 3, 4, 5, 6]
                elif level == "KJSEA":
                    level_grades = [7, 8, 9]
                else:
                    level_grades = []

                student_ids = []
                if level_grades:
                    placeholders = ",".join(["?"] * len(level_grades))
                    cursor.execute(
                        f"SELECT id FROM students WHERE grade IN ({placeholders})",
                        tuple(level_grades)
                    )
                    student_ids = [r[0] for r in cursor.fetchall()]

            if student_ids:
                placeholders = ",".join(["?"] * len(student_ids))
                cursor.execute(f"DELETE FROM results WHERE subject_id=? AND student_id IN ({placeholders})", [subject_id] + student_ids)
                cursor.execute(f"DELETE FROM candidate_targets WHERE subject_id=? AND student_id IN ({placeholders})", [subject_id] + student_ids)

        conn.commit()
        messagebox.showinfo("Deleted", f"Subject '{subject_name}' deleted from {level}{grade_label}")
        show_subjects()

    add_btn = tk.Button(add_frame,
              text="➕ Add Subject",
              bg=ACCENT_PURPLE,
              fg=TEXT_WHITE,
              command=add_subject, 
              font=("Arial", 10, "bold"),
              padx=12,
              pady=6)
    add_btn.pack(side="left")

    # Divider
    ttk.Separator(main_frame, orient="horizontal").pack(fill="x", padx=20, pady=15)

    # Get subjects by level
    cursor.execute(
        "SELECT DISTINCT s.name, sl.grade FROM subjects s "
        "JOIN subject_levels sl ON s.id=sl.subject_id "
        "WHERE sl.level='KPSEA' "
        "ORDER BY sl.grade, s.name"
    )
    kpsea_rows = cursor.fetchall()
    kpsea_subjects_by_grade = {}
    for subject, grade in kpsea_rows:
        kpsea_subjects_by_grade.setdefault(grade, []).append(subject)

    cursor.execute(
        "SELECT DISTINCT s.name, sl.grade FROM subjects s "
        "JOIN subject_levels sl ON s.id=sl.subject_id "
        "WHERE sl.level='KJSEA' "
        "ORDER BY sl.grade, s.name"
    )
    kjsea_rows = cursor.fetchall()
    kjsea_subjects_by_grade = {}
    for subject, grade in kjsea_rows:
        kjsea_subjects_by_grade.setdefault(grade, []).append(subject)

    if kpsea_rows or kjsea_rows:
        tk.Label(main_frame, text="Existing Subjects",
                 font=("Arial", 12, "bold"),
                 bg=BG_PRIMARY, fg=ACCENT_BLUE).pack(anchor="w", padx=20, pady=(0, 12))

        # Scrollable two-column container for subject listings
        scroll_wrapper = tk.Frame(main_frame, bg=BG_PRIMARY)
        scroll_wrapper.pack(fill="both", expand=True, padx=20, pady=(0, 20))

        canvas = tk.Canvas(scroll_wrapper, bg=BG_PRIMARY, highlightthickness=0)
        scrollbar = ttk.Scrollbar(scroll_wrapper, orient="vertical", command=canvas.yview)
        container = tk.Frame(canvas, bg=BG_PRIMARY)

        container_window = canvas.create_window((0, 0), window=container, anchor="nw")
        canvas.bind("<Configure>", lambda e: canvas.itemconfig(container_window, width=e.width))
        container.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )

        def on_mousewheel(event):
            if hasattr(event, 'delta') and event.delta:
                canvas.yview_scroll(int(-1 * (event.delta / 120)), 'units')
            elif event.num == 4:
                canvas.yview_scroll(-1, 'units')
            elif event.num == 5:
                canvas.yview_scroll(1, 'units')

        canvas.bind('<Enter>', lambda e: canvas.bind_all('<MouseWheel>', on_mousewheel))
        canvas.bind('<Leave>', lambda e: canvas.unbind_all('<MouseWheel>'))
        canvas.bind('<Button-4>', on_mousewheel)
        canvas.bind('<Button-5>', on_mousewheel)

        canvas.configure(yscrollcommand=scrollbar.set)
        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")

        # ===== LEFT SIDE: KPSEA =====
        left_frame = tk.Frame(container, bg=lighten_color(BG_PRIMARY, 0.05), relief="solid", bd=1)
        left_frame.pack(side="left", fill="both", expand=True, padx=(0, 10))

        kpsea_header = tk.Frame(left_frame, bg=ACCENT_ORANGE)
