# ================== EXAMS ================== #

def show_exams():
    clear_main()

    tk.Label(main_frame,
             text="📝 Exam Management",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=20)

    # Two options frame
    options_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    options_frame.pack(fill="x", padx=20, pady=20)

    tk.Button(
        options_frame,
        text="➕ Register Exam",
        bg=ACCENT_GREEN,
        fg=TEXT_WHITE,
        font=("Arial", 12),
        padx=20,
        pady=10,
        command=show_register_exam
    ).pack(side="left", padx=10)

    tk.Button(
        options_frame,
        text="📊 Analyze Results",
        bg=ACCENT_BLUE,
        fg=TEXT_WHITE,
        font=("Arial", 12),
        padx=20,
        pady=10,
        command=show_analyze_results
    ).pack(side="left", padx=10)

    # ------------------------------------------------------------------
    # list existing exams so the user can verify registration succeeded
    # ------------------------------------------------------------------
    no_exams_label = None
    def populate_exam_list():
        nonlocal no_exams_label
        for row in exam_tree.get_children():
            exam_tree.delete(row)
        if no_exams_label:
            no_exams_label.destroy()
            no_exams_label = None
        cursor.execute(
            "SELECT id, exam_id, name, start_date, end_date, duration_days FROM exams ORDER BY start_date DESC"
        )
        rows = cursor.fetchall()
        if not rows:
            no_exams_label = tk.Label(list_frame, text="No exams registered yet.", font=("Arial", 12), bg=BG_PRIMARY)
            no_exams_label.pack(pady=20)
            return
        
        # Alternate colors for rows (professional light blue alternating pattern)
        colors = ["#f8fbff", "#f0f7ff"]
        for idx, (exam_db_id, exam_id, name, start_date, end_date, duration) in enumerate(rows):
            color = colors[idx % 2]
            exam_tree.insert("", "end", values=(exam_id, name, start_date, end_date, f"{duration} days", exam_db_id), tags=(f'color{idx % 2}',))
        
        # Configure professional tag colors with better contrast
        exam_tree.tag_configure('color0', background='#f8fbff', foreground='#1a1a1a')
        exam_tree.tag_configure('color1', background='#f0f7ff', foreground='#1a1a1a')

    list_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    list_frame.pack(fill="both", expand=True, padx=20, pady=(0,20))
    
    # Define columns
    columns = ("Exam ID", "Name", "Start", "End", "Duration", "ID")
    
    # Create custom header frame for guaranteed visibility
    header_container = tk.Frame(list_frame, bg=ACCENT_BLUE, relief="raised", bd=2)
    header_container.pack(fill="x", pady=(0, 1))

    # Create header cells with exact column widths
    col_widths = [120, 120, 120, 120, 120, 0]  # Last column (ID) is hidden
    col_texts = ["🆔 Exam ID", "📝 Exam Name", "📅 Start Date", "📅 End Date", "⏱️ Duration", ""]

    for i, (text, width) in enumerate(zip(col_texts, col_widths)):
        if width > 0:  # Skip hidden column
            cell = tk.Frame(header_container, bg=ACCENT_BLUE, width=width, height=40)
            cell.pack(side="left", fill="y")
            cell.pack_propagate(False)
            lbl = tk.Label(cell, text=text, font=('Arial', 12, 'bold'), bg=ACCENT_BLUE, fg='white', anchor='center')
            lbl.pack(fill="both", expand=True)

    # Create Treeview without built-in headings (we have custom ones)
    exam_tree = ttk.Treeview(list_frame, columns=columns, show="")
    
    # Configure columns to match header widths exactly
    exam_tree.column("Exam ID", width=120, minwidth=100, anchor="center", stretch=False)
    exam_tree.column("Name", width=120, minwidth=100, anchor="center", stretch=False)
    exam_tree.column("Start", width=120, minwidth=100, anchor="center", stretch=False)
    exam_tree.column("End", width=120, minwidth=100, anchor="center", stretch=False)
    exam_tree.column("Duration", width=120, minwidth=100, anchor="center", stretch=False)
    exam_tree.column("ID", width=0, stretch=False)  # Hidden column
    
    # Add scrollbar and pack the tree
    scrollbar = ttk.Scrollbar(list_frame, orient="vertical", command=exam_tree.yview)
    exam_tree.configure(yscrollcommand=scrollbar.set)
    exam_tree.pack(fill="both", expand=True, side="left")
    scrollbar.pack(side="right", fill="y")
    scrollbar = ttk.Scrollbar(list_frame, orient="vertical", command=exam_tree.yview)
    exam_tree.configure(yscrollcommand=scrollbar.set)
    scrollbar.pack(side="right", fill="y")

    populate_exam_list()

    def view_selected():
        sel = exam_tree.selection()
        if not sel:
            messagebox.showinfo("Info", "Select an exam to view")
            return
        values = exam_tree.item(sel[0], "values")
        eid = values[0]
        name = values[1]
        start = values[2]
        end = values[3]
        duration = values[4]
        messagebox.showinfo("Exam Details", f"Exam ID: {eid}\nName: {name}\nStart: {start}\nEnd: {end}\nDuration: {duration}")

    def delete_selected():
        sel = exam_tree.selection()
        if not sel:
            messagebox.showinfo("Info", "Select an exam to delete")
            return
        values = exam_tree.item(sel[0], "values")
        eid = values[0]
        if messagebox.askyesno("Confirm", f"Delete exam '{eid}'? This cannot be undone."):
            cursor.execute("DELETE FROM exams WHERE exam_id=?", (eid,))
            conn.commit()
            populate_exam_list()

    btn_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    btn_frame.pack(fill="x", padx=20, pady=(0,10))
    tk.Button(btn_frame, text="👁️ View Selected", bg=ACCENT_BLUE, fg=TEXT_WHITE, command=view_selected).pack(side="left", padx=5)
    tk.Button(btn_frame, text="🗑️ Delete Selected", bg=ACCENT_RED, fg=TEXT_WHITE, command=delete_selected).pack(side="left", padx=5)


def show_register_exam():
    clear_main()

    # Back button
    tk.Button(main_frame, text="← Back", bg=ACCENT_PURPLE, fg=TEXT_WHITE, command=show_exams).pack(anchor="w", padx=20, pady=10)

    tk.Label(main_frame,
             text="➕ Register Exam",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=12)

    form_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    form_frame.pack(fill="both", expand=True, padx=20, pady=10)

    # Form fields
    fields = {}
    
    tk.Label(form_frame, text="Exam ID (leave blank to auto‑generate):", font=("Arial", 11), bg=BG_PRIMARY).pack(anchor="w", pady=(10, 0))
    exam_id_entry = tk.Entry(form_frame, width=40, font=("Arial", 11))
    exam_id_entry.pack(anchor="w", pady=(0, 10))
    fields["exam_id"] = exam_id_entry

    tk.Label(form_frame, text="Exam Name*:", font=("Arial", 11), bg=BG_PRIMARY).pack(anchor="w", pady=(10, 0))
    exam_name_entry = tk.Entry(form_frame, width=40, font=("Arial", 11))
    exam_name_entry.pack(anchor="w", pady=(0, 10))
    fields["exam_name"] = exam_name_entry

    # Starting Date with Calendar Picker
    tk.Label(form_frame, text="Starting Date*:", font=("Arial", 11), bg=BG_PRIMARY).pack(anchor="w", pady=(10, 0))
    start_date_frame = tk.Frame(form_frame, bg=BG_PRIMARY)
    start_date_frame.pack(anchor="w", pady=(0, 10), fill="x")
    
    start_date_entry = tk.Entry(start_date_frame, width=20, font=("Arial", 11))
    start_date_entry.insert(0, datetime.datetime.now().strftime("%Y-%m-%d"))
    start_date_entry.pack(side="left", padx=(0, 10))
    fields["start_date"] = start_date_entry
    
    def open_start_calendar():
        def on_date_selected(date_str):
            start_date_entry.delete(0, tk.END)
            start_date_entry.insert(0, date_str)
            update_duration()
            cal_window.destroy()
        
        cal_window = tk.Toplevel(root)
        cal_window.title("Select Start Date")
        cal_window.geometry("320x350")
        cal_window.transient(root)
        cal_window.grab_set()
        
        # Get current date from entry or use today
        try:
            current_date = datetime.datetime.strptime(start_date_entry.get(), "%Y-%m-%d")
        except:
            current_date = datetime.datetime.now()
        
        current_month = current_date.month
        current_year = current_date.year
        
        # Navigation frame
        nav_frame = tk.Frame(cal_window, bg=ACCENT_BLUE)
        nav_frame.pack(fill="x", padx=5, pady=5)
        
        month_year_label = tk.Label(nav_frame, text="", font=("Arial", 12, "bold"), bg=ACCENT_BLUE, fg=TEXT_WHITE)
        month_year_label.pack(pady=5)
        
        # Calendar grid
        cal_frame = tk.Frame(cal_window, bg=BG_PRIMARY)
        cal_frame.pack(fill="both", expand=True, padx=5, pady=5)
        
        def update_calendar():
            nonlocal current_month, current_year
            for widget in cal_frame.winfo_children():
                widget.destroy()
            
            month_year_label.config(text=f"{calendar.month_name[current_month]} {current_year}")
            
            # Days of week header
            days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
            for i, day in enumerate(days):
                tk.Label(cal_frame, text=day, font=("Arial", 9, "bold"), bg=ACCENT_BLUE, fg=TEXT_WHITE).grid(row=0, column=i, sticky="nsew", padx=2, pady=2)
            
            # Get calendar for month
            month_cal = calendar.monthcalendar(current_year, current_month)
            
            for week_idx, week in enumerate(month_cal, start=1):
                for day_idx, day in enumerate(week):
                    if day == 0:
                        tk.Label(cal_frame, text="", bg=BG_PRIMARY).grid(row=week_idx, column=day_idx, sticky="nsew", padx=2, pady=2)
                    else:
                        # Check if today
                        is_today = (day == current_date.day and current_month == current_date.month and current_year == current_date.year)
                        btn_bg = ACCENT_GREEN if is_today else ("#e8e8e8" if BG_PRIMARY == "#f6f8fa" else "#424242")
                        btn_fg = TEXT_WHITE if is_today else ("#222222" if BG_PRIMARY == "#f6f8fa" else "#e0e0e0")
                        
                        btn = tk.Button(
                            cal_frame,
                            text=str(day),
                            font=("Arial", 10),
                            bg=btn_bg,
                            fg=btn_fg,
                            command=lambda d=day: on_date_selected(f"{current_year:04d}-{current_month:02d}-{d:02d}")
                        )
                        btn.grid(row=week_idx, column=day_idx, sticky="nsew", padx=2, pady=2)
        
        # Navigation buttons frame
        btn_nav_frame = tk.Frame(nav_frame, bg=ACCENT_BLUE)
        btn_nav_frame.pack(fill="x", padx=5, pady=5)
        
        def prev_month():
            nonlocal current_month, current_year
            current_month -= 1
            if current_month < 1:
                current_month = 12
                current_year -= 1
            update_calendar()
        
        def next_month():
            nonlocal current_month, current_year
            current_month += 1
            if current_month > 12:
                current_month = 1
                current_year += 1
            update_calendar()
        
        tk.Button(btn_nav_frame, text="◀ Prev", bg=TEXT_WHITE, fg=ACCENT_BLUE, command=prev_month, font=("Arial", 9, "bold"), width=8).pack(side="left", padx=2)
        tk.Button(btn_nav_frame, text="Today", bg=TEXT_WHITE, fg=ACCENT_BLUE, command=lambda: (
            on_date_selected(datetime.datetime.now().strftime("%Y-%m-%d"))
        ), font=("Arial", 9, "bold"), width=8).pack(side="left", padx=2)
        tk.Button(btn_nav_frame, text="Next ▶", bg=TEXT_WHITE, fg=ACCENT_BLUE, command=next_month, font=("Arial", 9, "bold"), width=8).pack(side="left", padx=2)
        
        update_calendar()
    
    tk.Button(start_date_frame, text="📅 Calendar", bg=ACCENT_BLUE, fg=TEXT_WHITE, command=open_start_calendar, font=("Arial", 10)).pack(side="left")

    # Ending Date with Calendar Picker
    tk.Label(form_frame, text="Ending Date*:", font=("Arial", 11), bg=BG_PRIMARY).pack(anchor="w", pady=(10, 0))
    end_date_frame = tk.Frame(form_frame, bg=BG_PRIMARY)
    end_date_frame.pack(anchor="w", pady=(0, 10), fill="x")
    
    end_date_entry = tk.Entry(end_date_frame, width=20, font=("Arial", 11))
    end_date_entry.pack(side="left", padx=(0, 10))
    fields["end_date"] = end_date_entry
    
    def open_end_calendar():
        def on_date_selected(date_str):
            end_date_entry.delete(0, tk.END)
            end_date_entry.insert(0, date_str)
            update_duration()
            cal_window.destroy()
        
        cal_window = tk.Toplevel(root)
        cal_window.title("Select End Date")
        cal_window.geometry("320x350")
        cal_window.transient(root)
        cal_window.grab_set()
        
        # Get current date from entry or use today
        try:
            current_date = datetime.datetime.strptime(end_date_entry.get(), "%Y-%m-%d")
        except:
            current_date = datetime.datetime.now()
        
        current_month = current_date.month
        current_year = current_date.year
        
        # Navigation frame
        nav_frame = tk.Frame(cal_window, bg=ACCENT_BLUE)
        nav_frame.pack(fill="x", padx=5, pady=5)
        
        month_year_label = tk.Label(nav_frame, text="", font=("Arial", 12, "bold"), bg=ACCENT_BLUE, fg=TEXT_WHITE)
        month_year_label.pack(pady=5)
        
        # Calendar grid
        cal_frame = tk.Frame(cal_window, bg=BG_PRIMARY)
        cal_frame.pack(fill="both", expand=True, padx=5, pady=5)
        
        def update_calendar():
            nonlocal current_month, current_year
            for widget in cal_frame.winfo_children():
                widget.destroy()
            
            month_year_label.config(text=f"{calendar.month_name[current_month]} {current_year}")
            
            # Days of week header
            days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
            for i, day in enumerate(days):
                tk.Label(cal_frame, text=day, font=("Arial", 9, "bold"), bg=ACCENT_BLUE, fg=TEXT_WHITE).grid(row=0, column=i, sticky="nsew", padx=2, pady=2)
            
            # Get calendar for month
            month_cal = calendar.monthcalendar(current_year, current_month)
            
            for week_idx, week in enumerate(month_cal, start=1):
                for day_idx, day in enumerate(week):
                    if day == 0:
                        tk.Label(cal_frame, text="", bg=BG_PRIMARY).grid(row=week_idx, column=day_idx, sticky="nsew", padx=2, pady=2)
                    else:
                        # Check if today
                        is_today = (day == current_date.day and current_month == current_date.month and current_year == current_date.year)
                        btn_bg = ACCENT_GREEN if is_today else ("#e8e8e8" if BG_PRIMARY == "#f6f8fa" else "#424242")
                        btn_fg = TEXT_WHITE if is_today else ("#222222" if BG_PRIMARY == "#f6f8fa" else "#e0e0e0")
                        
                        btn = tk.Button(
                            cal_frame,
                            text=str(day),
                            font=("Arial", 10),
                            bg=btn_bg,
                            fg=btn_fg,
                            command=lambda d=day: on_date_selected(f"{current_year:04d}-{current_month:02d}-{d:02d}")
                        )
                        btn.grid(row=week_idx, column=day_idx, sticky="nsew", padx=2, pady=2)
        
        # Navigation buttons frame
        btn_nav_frame = tk.Frame(nav_frame, bg=ACCENT_BLUE)
        btn_nav_frame.pack(fill="x", padx=5, pady=5)
        
        def prev_month():
            nonlocal current_month, current_year
            current_month -= 1
            if current_month < 1:
                current_month = 12
                current_year -= 1
            update_calendar()
        
        def next_month():
            nonlocal current_month, current_year
            current_month += 1
            if current_month > 12:
                current_month = 1
                current_year += 1
            update_calendar()
        
        tk.Button(btn_nav_frame, text="◀ Prev", bg=TEXT_WHITE, fg=ACCENT_BLUE, command=prev_month, font=("Arial", 9, "bold"), width=8).pack(side="left", padx=2)
        tk.Button(btn_nav_frame, text="Today", bg=TEXT_WHITE, fg=ACCENT_BLUE, command=lambda: (
            on_date_selected(datetime.datetime.now().strftime("%Y-%m-%d"))
        ), font=("Arial", 9, "bold"), width=8).pack(side="left", padx=2)
        tk.Button(btn_nav_frame, text="Next ▶", bg=TEXT_WHITE, fg=ACCENT_BLUE, command=next_month, font=("Arial", 9, "bold"), width=8).pack(side="left", padx=2)
        
        update_calendar()
    
    tk.Button(end_date_frame, text="📅 Calendar", bg=ACCENT_BLUE, fg=TEXT_WHITE, command=open_end_calendar, font=("Arial", 10)).pack(side="left")

    tk.Label(form_frame, text="Exam Duration (Auto-calculated):", font=("Arial", 11, "bold"), bg=BG_PRIMARY, fg=ACCENT_BLUE).pack(anchor="w", pady=(10, 0))
    duration_label = tk.Label(form_frame, text="0 days", font=("Arial", 11), bg=BG_PRIMARY, fg=ACCENT_GREEN)
    duration_label.pack(anchor="w", pady=(0, 10))

    def update_duration(*args):
        try:
            start = datetime.datetime.strptime(start_date_entry.get().strip(), "%Y-%m-%d")
            end = datetime.datetime.strptime(end_date_entry.get().strip(), "%Y-%m-%d")
            duration = (end - start).days
            # make inclusive: if exam starts and ends same day it should still be 1 day
            if duration <= 0:
                duration = 1
            duration_label.config(text=f"{duration} days")
        except:
            duration_label.config(text="Invalid dates")

    start_date_entry.bind("<KeyRelease>", update_duration)
    end_date_entry.bind("<KeyRelease>", update_duration)

    tk.Label(form_frame, text="* Required fields (exam ID may be left blank)", font=("Arial", 9, "italic"), bg=BG_PRIMARY, fg="#e74c3c").pack(anchor="w", pady=(10, 10))

    # Bind Enter key to move between fields
    entry_fields = [exam_id_entry, exam_name_entry, start_date_entry, end_date_entry]
    bind_enter_to_next_field(entry_fields)

    def save_exam():
        try:
            exam_id = fields["exam_id"].get().strip()
            exam_name = fields["exam_name"].get().strip()
            start_date = fields["start_date"].get().strip()
            end_date = fields["end_date"].get().strip()

            # exam_id is optional; if user left it empty we generate one based on the
            # current timestamp.  This prevents the most common user complaint of
            # "nothing happens when I save" because they forgot to type an ID.
            if not exam_id:
                exam_id = generate_exam_id()
            
            # Validate exam_id (alphanumeric, no special chars except hyphen/underscore)
            if not exam_id.replace("-", "").replace("_", "").isalnum():
                messagebox.showerror("Error", "Invalid Exam ID.\nUse only letters, numbers, hyphens, or underscores.")
                return
            
            # Validate exam name
            if not exam_name:
                messagebox.showerror("Error", "Exam name is required")
                return
            if len(exam_name) > 100:
                messagebox.showerror("Error", "Exam name too long (max 100 characters)")
                return

            if not all([start_date, end_date]):
                messagebox.showerror("Error", "Start and end dates are required")
                return

            # Validate dates format and values
            try:
                start = datetime.datetime.strptime(start_date, "%Y-%m-%d")
                end = datetime.datetime.strptime(end_date, "%Y-%m-%d")
            except ValueError:
                messagebox.showerror("Error", "Invalid date format.\nUse YYYY-MM-DD (e.g., 2026-03-15)")
                return

            if end < start:
                messagebox.showerror("Error", "Ending date must be after or equal to starting date")
                return
            
            # Check if exam_id already exists
            cursor.execute("SELECT id FROM exams WHERE exam_id = ?", (exam_id,))
            if cursor.fetchone():
                messagebox.showerror("Error", f"Exam ID '{exam_id}' already exists.\nPlease use a unique ID.")
                return

            duration = (end - start).days
            if duration <= 0:  # same-day exam still counts as 1 day
                duration = 1

            cursor.execute(
                "INSERT INTO exams(exam_id, name, start_date, end_date, duration_days) VALUES(?,?,?,?,?)",
                (exam_id, exam_name, start_date, end_date, duration)
            )
            conn.commit()
            messagebox.showinfo("Success", f"Exam '{exam_name}' (ID: {exam_id}) registered with {duration} days duration")
            show_exams()
        except ValueError as e:
            messagebox.showerror("Error", "Invalid date format. Use YYYY-MM-DD")
        except sqlite3.IntegrityError:
            messagebox.showerror("Error", "Exam ID already exists")
        except Exception as e:
            # unexpected error – log to console and show message so user knows
            print("Unexpected error saving exam:", e)
            messagebox.showerror("Error", f"An unexpected error occurred: {e}")

    tk.Button(main_frame, text="✓ Save Exam", bg=ACCENT_GREEN, fg=TEXT_WHITE, padx=20, pady=10, command=save_exam).pack(pady=20)


