def show_exams_by_level(level):
    clear_main()

    # Back button
    tk.Button(main_frame, text="← Back", bg=ACCENT_PURPLE, fg=TEXT_WHITE, command=show_analyze_results).pack(anchor="w", padx=20, pady=10)

    level_name = "KPSEA (Grades 1-6)" if level == "KPSEA" else "KJSEA (Grades 7-9)"
    level_icon = "📘" if level == "KPSEA" else "📗"
    tk.Label(main_frame,
             text=f"{level_icon} {level_name} - Select Grade",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=12)

    # always allow selection of every grade in the level
    if level == "KPSEA":
        grades = list(range(1, 7))
    else:
        grades = list(range(7, 10))
    # (we don't block grades with no existing results; calling
    # show_exams_for_grade will simply show the "no results" warning per
    # exam card if nothing recorded yet.)

    # Add quick graph showing number of students in each grade for this level
    graph_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    graph_frame.pack(fill="both", expand=False, padx=20, pady=(0,20))
    def plot_grade_counts():
        cursor.execute("SELECT grade, COUNT(*) FROM students WHERE level=? GROUP BY grade ORDER BY grade", (level,))
        rows = cursor.fetchall()
        if rows:
            grds = [r[0] for r in rows]
            counts = [r[1] for r in rows]
        else:
            grds = grades
            counts = [0]*len(grades)

        fig = plt.Figure(figsize=(4,2), dpi=80)
        ax = fig.add_subplot(111)
        ax.bar([str(g) for g in grds], counts, color=ACCENT_GREEN)
        ax.set_title(f"Students per Grade ({level})")
        ax.set_xlabel("Grade")
        ax.set_ylabel("Count")
        ax.grid(axis='y', linestyle='--', alpha=0.3)
        fig.tight_layout()
        canvas = FigureCanvasTkAgg(fig, master=graph_frame)
        canvas.draw()
        canvas.get_tk_widget().pack(fill="both", expand=True)

    plot_grade_counts()

    btn_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    btn_frame.pack(fill="x", padx=20, pady=20)
    for g in grades:
        tk.Button(btn_frame, text=f"Grade {g}", bg=ACCENT_BLUE, fg=TEXT_WHITE,
                  font=("Arial", 12), padx=20, pady=10,
                  command=lambda g=g: show_exams_for_grade(level, g)).pack(side="left", padx=6, expand=True, fill="x")


def show_exams_for_grade(level, grade):
    # previous implementation moved here, with filtering by grade
    clear_main()

    tk.Button(main_frame, text="← Back", bg=ACCENT_PURPLE, fg=TEXT_WHITE,
              command=lambda: show_exams_by_level(level)).pack(anchor="w", padx=20, pady=10)

    level_name = "KPSEA (Grades 1-6)" if level == "KPSEA" else "KJSEA (Grades 7-9)"
    level_icon = "📘" if level == "KPSEA" else "📗"
    tk.Label(main_frame,
             text=f"{level_icon} {level_name} - Grade {grade} Exams",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=12)

    cursor.execute(
        "SELECT id, exam_id, name, start_date, end_date, duration_days FROM exams ORDER BY start_date DESC"
    )
    all_exams = cursor.fetchall()

    if not all_exams:
        tk.Label(main_frame, text="No exams registered yet.", font=("Arial", 12), bg=BG_PRIMARY).pack(pady=20)
        return

    # Search frame with total count
    search_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    search_frame.pack(fill="x", padx=20, pady=12)

    # Total exams label
    total_label = tk.Label(search_frame, text=f"Total Exams: {len(all_exams)}", font=("Arial", 11, "bold"), bg=BG_PRIMARY, fg=ACCENT_BLUE)
    total_label.pack(side="left", padx=(0, 20))

    tk.Label(search_frame, text="Search Exams:", font=("Arial", 11, "bold"), bg=BG_PRIMARY).pack(side="left", padx=(0, 10))
    search_var = tk.StringVar()
    search_entry = tk.Entry(search_frame, textvariable=search_var, width=30, font=("Arial", 11))
    search_entry.pack(side="left", padx=(0, 10))

    def update_exam_grid(search_term=""):
        # Clear existing cards
        for widget in grid_frame.winfo_children():
            widget.destroy()

        # Filter exams based on search term
        filtered_exams = []
        for exam in all_exams:
            exam_id, exam_code, name, start_date, end_date, duration = exam
            if search_term.lower() in exam_code.lower() or search_term.lower() in name.lower():
                filtered_exams.append(exam)

        if not filtered_exams:
            no_result = tk.Label(grid_frame, text="No exams match your search.", font=("Arial", 12), bg=BG_PRIMARY)
            no_result.pack(pady=20)
            return

        # Update total count label
        total_label.config(text=f"Total Exams: {len(all_exams)} | Showing: {len(filtered_exams)}")

        # Determine number of columns based on available width so cards stay compact
        frame_w = grid_frame.winfo_width()
        if frame_w > 1:
            cols = max(2, frame_w // 150)
        else:
            cols = 6

        # Create grid layout (cols computed dynamically)
        for idx, (exam_id, exam_code, name, start_date, end_date, duration) in enumerate(filtered_exams):
            cursor.execute("""
                SELECT 1 FROM results r
                JOIN students s ON r.student_id = s.id
                WHERE r.exam_id = ? AND s.level = ? AND s.grade = ?
                LIMIT 1
            """, (exam_id, level, grade))
            has_results = cursor.fetchone() is not None

            # Alternate card colors
            card_colors = [ACCENT_BLUE, ACCENT_PURPLE, ACCENT_ORANGE, ACCENT_GREEN]
            card_bg = card_colors[idx % len(card_colors)]
            card_hover = lighten_color(card_bg, 0.15)

            # Properly sized exam card with adequate space for Enter button
            card_frame = tk.Frame(grid_frame, bg=card_bg, bd=0, relief="flat", width=150, height=90)
            card_frame.pack_propagate(False)
            card_frame.grid(row=idx // cols, column=idx % cols, padx=4, pady=3, sticky="nsew")

            # Add hover effect
            def on_enter(event, frame=card_frame, color=card_hover):
                frame.config(bg=color)
                for child in frame.winfo_children():
                    if isinstance(child, tk.Frame):
                        child.config(bg=color)
                        for subchild in child.winfo_children():
                            if isinstance(subchild, tk.Label):
                                subchild.config(bg=color)

            def on_leave(event, frame=card_frame, color=card_bg):
                frame.config(bg=color)
                for child in frame.winfo_children():
                    if isinstance(child, tk.Frame):
                        child.config(bg=color)
                        for subchild in child.winfo_children():
                            if isinstance(subchild, tk.Label):
                                subchild.config(bg=color)

            card_frame.bind("<Enter>", on_enter)
            card_frame.bind("<Leave>", on_leave)

            content_frame = tk.Frame(card_frame, bg=card_bg)
            content_frame.pack(fill="both", expand=True, padx=6, pady=5)

            # Top section: Icon and Exam Code
            header_frame = tk.Frame(content_frame, bg=card_bg)
            header_frame.pack(fill="x", pady=(0, 2))

            tk.Label(header_frame, text="📝", font=("Arial", 10), bg=card_bg, fg=TEXT_WHITE).pack(side="left", padx=(0, 4))
            tk.Label(header_frame, text=exam_code, font=("Arial", 8, "bold"), bg=card_bg, fg=TEXT_WHITE, wraplength=120, justify="left").pack(side="left", expand=True, anchor="w")

            # small delete button for this exam card
            def delete_exam_card(eid=exam_id):
                if not messagebox.askyesno("Confirm", f"Delete exam '{exam_code}'? This will remove all related results."):
                    return
                try:
                    cursor.execute("DELETE FROM results WHERE exam_id=?", (eid,))
                    cursor.execute("DELETE FROM exams WHERE id=?", (eid,))
                    conn.commit()
                    update_exam_grid(search_var.get())
                except Exception as e:
                    messagebox.showerror("Error", f"Failed to delete exam: {e}")

            tk.Button(header_frame, text="🗑️", bg=TEXT_WHITE, fg=card_bg, font=("Arial", 7), padx=4, pady=1, bd=0, command=delete_exam_card).pack(side="right")

            # Exam Name
            tk.Label(content_frame, text=name, font=("Arial", 8), bg=card_bg, fg=lighten_color(card_bg, 0.2), wraplength=130, justify="left").pack(anchor="w", pady=(0, 2))

            # Date info
            info_text = f"📅 {start_date}"
            tk.Label(content_frame, text=info_text, font=("Arial", 7), bg=card_bg, fg=lighten_color(card_bg, 0.25)).pack(anchor="w", pady=(0, 1))

            # Duration
            duration_text = f"⏱️ {duration}d"
            tk.Label(content_frame, text=duration_text, font=("Arial", 7), bg=card_bg, fg=lighten_color(card_bg, 0.25)).pack(anchor="w", pady=(0, 2))

            # Status
            if has_results:
                tk.Label(content_frame, text="✓ Done", font=("Arial", 6, "bold"), bg=card_bg, fg=ACCENT_GREEN).pack(anchor="w")
            else:
                tk.Label(content_frame, text="⚠️ Pending", font=("Arial", 6, "bold"), bg=card_bg, fg=ACCENT_ORANGE).pack(anchor="w")

            def analyze_selected(eid=exam_id, gr=grade):
                start_marking(eid, level, gr)

            btn = tk.Button(
                content_frame,
                text="Enter",
                bg=TEXT_WHITE,
                fg=card_bg,
                font=("Arial", 8, "bold"),
                padx=8,
                pady=3,
                bd=0,
                command=analyze_selected
            )
            btn.pack(pady=(4, 0), fill="x")

        # Configure grid weights for proper distribution
        for i in range((len(filtered_exams) + cols - 1) // cols):
            grid_frame.grid_rowconfigure(i, weight=1)
        for i in range(cols):
            grid_frame.grid_columnconfigure(i, weight=1)

    def on_search(*args):
        update_exam_grid(search_var.get())

    search_entry.bind("<KeyRelease>", on_search)
    tk.Button(search_frame, text="🔍 Search", bg=ACCENT_BLUE, fg=TEXT_WHITE, padx=15, pady=6, command=lambda: update_exam_grid(search_var.get())).pack(side="left")

    # Grid container
    grid_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    grid_frame.pack(fill="both", expand=True, padx=20, pady=10)

    # ensure grid updates on resize so cards adapt
    grid_frame.bind('<Configure>', lambda e: update_exam_grid(search_var.get()))

    # Initial load
    update_exam_grid()


def show_exam_analysis(exam_id, exam_code, exam_name, level, grade=None):
    clear_main()

    # Back button navigates to grade or level list
    if grade is not None:
        tk.Button(main_frame, text="← Back", bg=ACCENT_PURPLE, fg=TEXT_WHITE,
                  command=lambda: show_exams_for_grade(level, grade)).pack(anchor="w", padx=20, pady=10)
    else:
        tk.Button(main_frame, text="← Back", bg=ACCENT_PURPLE, fg=TEXT_WHITE, command=show_analyze_results).pack(anchor="w", padx=20, pady=10)

    level_name = "KPSEA (Grades 1-6)" if level == "KPSEA" else "KJSEA (Grades 7-9)"
    tk.Label(main_frame,
             text=f"📈 Results Analysis - {exam_name} ({exam_code}) - {level_name}",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=12)

    # selection area for grade and subject
    control_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    control_frame.pack(fill="x", padx=20, pady=10)

    tk.Label(control_frame, text="Grade:", font=("Arial", 11), bg=BG_PRIMARY).pack(side="left")
    grade_var = tk.IntVar(value=grade if grade is not None else 1)
    grade_combo = ttk.Combobox(control_frame, textvariable=grade_var, values=list(range(1, 10)), width=5, state="readonly")
    grade_combo.pack(side="left", padx=5)
    if grade is not None:
        grade_combo.config(state="disabled")

    tk.Label(control_frame, text="Subject:", font=("Arial", 11), bg=BG_PRIMARY).pack(side="left", padx=(20,0))
    def load_subjects_for_analysis(selected_grade):
        if level == "KPSEA":
            subj_list = get_subjects_for_level_and_grade(level, selected_grade)
        else:
            subj_list = get_subjects_for_level_and_grade(level)
        return subj_list

    subjects = load_subjects_for_analysis(grade_var.get())
    subject_var = tk.StringVar(value=subjects[0] if subjects else "")
    subject_combo = ttk.Combobox(control_frame, textvariable=subject_var, values=subjects, width=20, state="readonly")
    subject_combo.pack(side="left", padx=5)

    def on_grade_change_for_analysis(*_):
        subs = load_subjects_for_analysis(grade_var.get())
        subject_combo.config(values=subs)
        if subs:
            subject_var.set(subs[0])
        else:
            subject_var.set("")

    grade_var.trace_add("write", on_grade_change_for_analysis)
    def begin_marking():
        grade_sel = grade_var.get()
        subj = subject_var.get().strip()
        if not subj:
            messagebox.showerror("Error", "No subjects available")
            return
        show_marking_window(exam_id, level, grade_sel, initial_subject=subj)

    tk.Button(control_frame, text="Start", bg=ACCENT_GREEN, fg=TEXT_WHITE, command=begin_marking).pack(side="left", padx=(20,0))

    # container for results table (just for quick view)
    # the table will remain below controls after marking is done


# ================== REPORTS ================== #

def show_reports():
    clear_main()

    tk.Label(main_frame,
             text="📊 Reports",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=20)

    options_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    options_frame.pack(fill="x", padx=20, pady=10)

    tk.Button(options_frame, text="📄 Exam Reports", bg=ACCENT_BLUE, fg=TEXT_WHITE, padx=20, pady=8, command=show_exam_reports).pack(side="left", padx=10)
    tk.Button(options_frame, text="📈 Exam Analysis Graphs", bg=ACCENT_PURPLE, fg=TEXT_WHITE, padx=20, pady=8, command=show_exam_analysis_graphs).pack(side="left", padx=10)

    # Candidates Performance section
    ttk.Separator(main_frame, orient='horizontal').pack(fill='x', padx=20, pady=(10, 10))

    tk.Label(main_frame,
             text="🎯 Candidates Performance (Grade 9 - KJSEA)",
             font=("Arial", 14, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=(10, 10))

    plot_holder = {'frame': None, 'summary_frame': None, 'btn_frame': None}

    def plot_candidates():
        # Clear previous candidates graphs
        if plot_holder.get('frame'):
            plot_holder['frame'].destroy()
        if plot_holder.get('summary_frame'):
            plot_holder['summary_frame'].destroy()
        if plot_holder.get('btn_frame'):
            plot_holder['btn_frame'].destroy()

        # Fetch subjects that have actual results for grade 9 candidates
        cursor.execute(
            "SELECT DISTINCT s.name FROM subjects s "
            "JOIN results r ON s.id=r.subject_id "
            "JOIN students st ON r.student_id=st.id "
            "WHERE st.grade=9 "
            "ORDER BY s.name"
        )
        subjects_rows = cursor.fetchall()
        if not subjects_rows:
            tk.Label(main_frame, text="No subjects found with results for grade 9 candidates.", font=("Arial", 12), bg=BG_PRIMARY).pack(pady=20)
            return
        subjects = [row[0] for row in subjects_rows]

        # compute average target points per subject from candidate_targets table
        subject_target_avgs = {}
        cursor.execute("SELECT COUNT(*) FROM candidate_targets")
        count_targets = cursor.fetchone()[0]
        if count_targets > 0:
            for subj in subjects:
                cursor.execute(
                    "SELECT ct.target FROM candidate_targets ct "
                    "JOIN subjects s ON ct.subject_id=s.id "
                    "WHERE s.name=?",
                    (subj,)
                )
                marks_list = [r[0] for r in cursor.fetchall() if r[0] is not None]
                if marks_list:
                    pts_list = [marks_to_points(m) for m in marks_list]
                    subject_target_avgs[subj] = sum(pts_list) / len(pts_list)
                else:
                    subject_target_avgs[subj] = 0
        else:
            # fall back to global mean if no per-student targets have been entered
            _, _, mean_target = load_candidate_targets()
            for subj in subjects:
                subject_target_avgs[subj] = mean_target if mean_target else 0

        # Create target line data
        target_line_data = [subject_target_avgs.get(subj, 0) for subj in subjects]
        # overall mean of targets (used for comparisons/legend)
        overall_target = sum(target_line_data) / len(target_line_data) if target_line_data else 0

        # Fetch all marks per subject and convert to points to compute average
        subject_avgs_all_exams = {}
        for subj in subjects:
            cursor.execute(
                "SELECT r.marks FROM results r "
                "JOIN students s ON s.id=r.student_id "
                "JOIN subjects subj ON r.subject_id=subj.id "
                "WHERE s.grade=9 AND subj.name=?",
                (subj,)
            )
            pts_list = [marks_to_points(row[0]) for row in cursor.fetchall()]
            avg_pts = sum(pts_list) / len(pts_list) if pts_list else 0
            subject_avgs_all_exams[subj] = avg_pts

        # Prepare data for plotting - only subjects with actual averages
        subj_names = list(subject_avgs_all_exams.keys())
        actual_avgs = list(subject_avgs_all_exams.values())
        
        # Filter target_line_data to only include subjects that have results
        target_line_data = [subject_target_avgs.get(subj, 0) for subj in subj_names]
        overall_target = sum(target_line_data) / len(target_line_data) if target_line_data else 0

        # Calculate overall mean of all subject averages (points)
        overall_mean = sum(actual_avgs) / len(actual_avgs) if actual_avgs else 0

        # compute mean points of candidates (average of per-student point means)
        cursor.execute(
            "SELECT r.student_id, r.marks FROM results r "
            "JOIN students s ON s.id=r.student_id "
            "WHERE s.grade=9"
        )
        data = cursor.fetchall()
        stu_pts = {}
        for sid, mark in data:
            stu_pts.setdefault(sid, []).append(marks_to_points(mark))
        student_means = [sum(lst) / len(lst) for lst in stu_pts.values()] if stu_pts else []
        candidate_mean_points = sum(student_means) / len(student_means) if student_means else 0

        # Create figure with line chart
        fig_cand = plt.Figure(figsize=(10, 5), dpi=100)
        ax_cand = fig_cand.add_subplot(111)

        # Prepare x-axis positions
        x_pos = range(len(subj_names))

        # Plot two line graphs
        ax_cand.plot(x_pos, target_line_data, color=ACCENT_RED, linestyle='-', linewidth=2.5, marker='o', markersize=6, label=f'Target Mean Points: {overall_target:.1f}')
        ax_cand.plot(x_pos, actual_avgs, color=ACCENT_GREEN, linestyle='-', linewidth=2.5, marker='s', markersize=6, label=f'Subject Mean Points: {overall_mean:.1f}')
        # horizontal line for candidate average points
        ax_cand.axhline(y=candidate_mean_points, color=ACCENT_PURPLE, linestyle='--', linewidth=2, label=f'Candidates Mean: {candidate_mean_points:.1f}')

        ax_cand.set_xticks(x_pos)
        ax_cand.set_xticklabels(subj_names, rotation=45, ha='right', fontsize=10)
        ax_cand.set_ylabel('Average Points (0–8)')
        ax_cand.set_xlabel('Subject')
        ax_cand.set_title('Grade 9 Candidates: Target vs Actual Performance by Subject')
        ax_cand.set_ylim(0, 8)
        ax_cand.grid(True, linestyle='--', alpha=0.3)
        ax_cand.legend(fontsize=10)
        fig_cand.tight_layout()

        # Embed graph
        cand_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
        cand_frame.pack(fill='both', expand=True, padx=20, pady=12)
        plot_holder['frame'] = cand_frame
        canvas_cand = FigureCanvasTkAgg(fig_cand, master=cand_frame)
        canvas_cand.draw()
        canvas_cand.get_tk_widget().pack(fill='both', expand=True)

        # Summary panel
        summary_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
        summary_frame.pack(fill='x', padx=20, pady=(0, 12))
        plot_holder['summary_frame'] = summary_frame
        summary_text = f"Total Subjects: {len(subj_names)} | Subject Mean: {overall_mean:.2f} | Candidate Mean: {candidate_mean_points:.2f}"
        # use overall_target calculated earlier (could be from individual student targets or global fallback)
        status = "✓ On Target" if candidate_mean_points >= overall_target else "✗ Below Target"
        summary_text += f" | Target Points: {overall_target:.2f} | Status: {status}"
        tk.Label(summary_frame, text=summary_text, font=("Arial", 11), bg=BG_PRIMARY, fg="#333").pack(anchor="w")

        # Export button
        btn_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
        btn_frame.pack(fill='x', padx=20, pady=(0, 12))
        plot_holder['btn_frame'] = btn_frame
        
        def export_candidates_pdf():
            fname = filedialog.asksaveasfilename(defaultextension='.pdf', filetypes=[('PDF','*.pdf')], title='Save candidates graph as PDF')
            if not fname:
                return
            from matplotlib.backends.backend_pdf import PdfPages
            pp = PdfPages(fname)
            pp.savefig(fig_cand, bbox_inches='tight')
            pp.close()
            messagebox.showinfo('Saved', f'Candidates graph saved to {fname}')
        
        tk.Button(btn_frame, text='Export PDF', bg=ACCENT_GREEN, fg=TEXT_WHITE, command=export_candidates_pdf).pack(side='left')

    # Load candidates graph on init
    plot_candidates()


def show_exam_reports():
    clear_main()

    tk.Label(main_frame,
             text="� Exam Reports",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=20)

    # Filter and search bar
    filter_frame = tk.Frame(main_frame, bg=BG_PRIMARY)
    filter_frame.pack(fill="x", padx=20, pady=(0,10))
    
    # Exam filter dropdown
    tk.Label(filter_frame, text="Filter by Exam:", bg=BG_PRIMARY, font=("Arial", 9, "bold")).pack(side="left")
    
    # Fetch all exams for dropdown
    cursor.execute("SELECT DISTINCT id, exam_id, name FROM exams ORDER BY start_date DESC")
    exam_list = cursor.fetchall()
    exam_options = ["All Exams"] + [f"{code} - {name}" for _, code, name in exam_list]
    exam_id_map = {"All Exams": ""} | {f"{code} - {name}": code for _, code, name in exam_list}
    
    exam_filter_var = tk.StringVar(value="All Exams")
    exam_combo = ttk.Combobox(filter_frame, textvariable=exam_filter_var, values=exam_options, width=35, state="readonly")
    exam_combo.pack(side="left", padx=8)
    
    def on_exam_filter_changed(*args):
        selected = exam_filter_var.get()
        exam_code = exam_id_map.get(selected, "")
        show_exam_reports_filtered(exam_code)
    
    exam_filter_var.trace_add("write", on_exam_filter_changed)
    
    # Optional: Keep text search as secondary filter
    tk.Label(filter_frame, text="Search:", bg=BG_PRIMARY, font=("Arial", 9, "bold")).pack(side="left", padx=(20, 0))
    examsearch_var = tk.StringVar()
    search_entry = tk.Entry(filter_frame, textvariable=examsearch_var, width=20)
    search_entry.pack(side="left", padx=5)
    
    def do_search():
        selected = exam_filter_var.get()
        exam_code = exam_id_map.get(selected, "")
        search_term = examsearch_var.get().strip()
        # Combine filter and search
        if exam_code and search_term:
            combined = f"{exam_code} {search_term}"
        elif search_term:
            combined = search_term
        else:
            combined = exam_code
        show_exam_reports_filtered(combined)
    
    tk.Button(filter_frame, text="🔍 Search", command=do_search, bg=ACCENT_BLUE, fg=TEXT_WHITE, font=("Arial", 9, "bold")).pack(side="left", padx=5)

    # initial load all
    show_exam_reports_filtered("")


def show_exam_reports_filtered(exam_id_filter):
    # called internally by search and initial load
    # clear previous widgets except search frame
    for widget in main_frame.winfo_children():
        if isinstance(widget, ttk.Scrollbar) or (isinstance(widget, tk.Canvas)):
            widget.destroy()
    
    query = """
    SELECT DISTINCT e.id, e.exam_id, e.name, s.grade, s.level
    FROM exams e
    LEFT JOIN results r ON e.id = r.exam_id
    LEFT JOIN students s ON r.student_id = s.id
    """
    params = []
    if exam_id_filter:
        query += " WHERE e.exam_id LIKE ?"
        params.append(f"%{exam_id_filter}%")
    query += " ORDER BY e.start_date DESC"
    cursor.execute(query, params)
    exam_rows = cursor.fetchall()

    if not exam_rows:
        tk.Label(main_frame, text="No exam reports found.", font=("Arial", 12), bg=BG_PRIMARY).pack(pady=20)
        return

    # Create scrollable frame for reports
    canvas = tk.Canvas(main_frame, bg=BG_PRIMARY, highlightthickness=0)
    scrollbar = ttk.Scrollbar(main_frame, orient="vertical", command=canvas.yview)
    scrollable_frame = tk.Frame(canvas, bg=BG_PRIMARY)

    scrollable_frame.bind(
        "<Configure>",
        lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
    )

    canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
    canvas.configure(yscrollcommand=scrollbar.set)

    # Create book-like report cards for each exam in 2-column grid
    col = 0
    row = 0
    for exam_id, exam_code, exam_name in cursor.execute("SELECT DISTINCT e.id, e.exam_id, e.name FROM exams e ORDER BY e.start_date DESC").fetchall():
        # Get detailed exam info
        cursor.execute("SELECT start_date, end_date FROM exams WHERE id=?", (exam_id,))
        exam_info = cursor.fetchone()
        start_date = exam_info[0] if exam_info else ""

        # Create report header with exam name (no grade - general for all)
        report_label_text = f"{exam_code} - {exam_name}"
        
        # Book-like container in grid
        report_frame = tk.Frame(scrollable_frame, bg=TEXT_WHITE, bd=2, relief="solid", width=500, height=350)
        report_frame.pack_propagate(False)
        report_frame.grid(row=row, column=col, padx=10, pady=12, sticky="nsew")

        # Header section (like a book cover/title) - GREEN HEADER
        header_frame = tk.Frame(report_frame, bg=ACCENT_GREEN)
        header_frame.pack(fill="x", padx=0, pady=0)

        tk.Label(header_frame, text=report_label_text, font=("Arial", 12, "bold"), bg=ACCENT_GREEN, fg=TEXT_WHITE, padx=15, pady=10).pack(anchor="w", fill="x")

        # Action buttons frame
        actions_frame = tk.Frame(report_frame, bg="#f0f0f0")
        actions_frame.pack(fill="x", padx=10, pady=8)

        def view_grade_report(eid=exam_id):
            show_grade_report(eid)

        def view_student_ranking(eid=exam_id):
            show_student_ranking(eid)

        def view_subject_ranking(eid=exam_id):
            show_subject_ranking(eid)

        def view_previous_comparison(eid=exam_id):
            show_prev_comparison(eid)

        def delete_exam_report(eid=exam_id, ecode=exam_code):
            if not messagebox.askyesno("Confirm", f"Delete exam '{ecode}'? This will remove all related results."):
                return
            try:
                cursor.execute("DELETE FROM results WHERE exam_id=?", (eid,))
                cursor.execute("DELETE FROM exams WHERE id=?", (eid,))
                conn.commit()
                show_exam_reports()
            except Exception as e:
                messagebox.showerror("Error", f"Failed to delete exam: {e}")

        tk.Button(actions_frame, text="📑 Grade", bg=ACCENT_BLUE, fg=TEXT_WHITE, 
                 padx=8, pady=4, font=("Arial", 8, "bold"), command=view_grade_report).pack(side="left", padx=2)
        tk.Button(actions_frame, text="🏆 Ranking", bg=ACCENT_GREEN, fg=TEXT_WHITE, 
                 padx=8, pady=4, font=("Arial", 8, "bold"), command=view_student_ranking).pack(side="left", padx=2)
        tk.Button(actions_frame, text="📊 Subjects", bg=ACCENT_ORANGE, fg=TEXT_WHITE, 
                 padx=8, pady=4, font=("Arial", 8, "bold"), command=view_subject_ranking).pack(side="left", padx=2)
        tk.Button(actions_frame, text="🔁 Compare", bg=ACCENT_PURPLE, fg=TEXT_WHITE, 
                 padx=8, pady=4, font=("Arial", 8, "bold"), command=view_previous_comparison).pack(side="left", padx=2)
        tk.Button(actions_frame, text="🗑️ Delete", bg=ACCENT_RED, fg=TEXT_WHITE, 
                 padx=8, pady=4, font=("Arial", 8, "bold"), command=delete_exam_report).pack(side="left", padx=2)

        # Content area
        content_frame = tk.Frame(report_frame, bg=TEXT_WHITE)
        content_frame.pack(fill="both", expand=True, padx=10, pady=10)

        # Exam details
        tk.Label(content_frame, text=f"ID: {exam_code} | Date: {start_date}", 
                font=("Arial", 8), bg=TEXT_WHITE, fg="#666666").pack(anchor="w", pady=(0,6))

        # Get all results for this exam (all grades)
        cursor.execute("""
            SELECT s.student_name, s.admission_number, subj.name, r.marks
            FROM results r
            JOIN students s ON r.student_id = s.id
            JOIN subjects subj ON r.subject_id = subj.id
            WHERE r.exam_id = ?
            ORDER BY s.student_name, subj.name
        """, (exam_id,))
        results = cursor.fetchall()

        if results:
            # Calculate data for circular graphs - students per grade by level
            cursor.execute("""
                SELECT s.grade, s.level, COUNT(DISTINCT s.id) as student_count
                FROM results r
                JOIN students s ON r.student_id = s.id
                WHERE r.exam_id = ?
                GROUP BY s.grade, s.level
                ORDER BY s.grade
            """, (exam_id,))
            
            grade_stats = cursor.fetchall()
            
            # Separate data by level (KPSEA: grades 1-6, KJSEA: grades 7-9)
            kpsea_grades = {}
            kjsea_grades = {}
            
            for grade, level, count in grade_stats:
                if level == "KPSEA" or grade <= 6:
                    kpsea_grades[f"Grade {grade}"] = count
                else:
                    kjsea_grades[f"Grade {grade}"] = count
            
            # Create circular graph display frame
            graph_container = tk.Frame(content_frame, bg=TEXT_WHITE)
            graph_container.pack(fill="both", expand=True, pady=(4,0))
            
            # Create two pie charts side by side
            fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(10, 3.5))
            fig.patch.set_facecolor(TEXT_WHITE)
            
            # KPSEA Pie Chart (Left)
            if kpsea_grades:
                grades_kpsea = list(kpsea_grades.keys())
                counts_kpsea = list(kpsea_grades.values())
                colors_kpsea = ['#3498db', '#2ecc71', '#f39c12', '#e74c3c', '#9b59b6', '#1abc9c']
                
                wedges1, texts1, autotexts1 = ax1.pie(counts_kpsea, labels=grades_kpsea, autopct='%1.0f%%',
                                                       colors=colors_kpsea[:len(counts_kpsea)],
                                                       startangle=90, textprops={'fontsize': 8, 'weight': 'bold'})
                ax1.set_title("KPSEA\n(Primary Grades 1-6)", fontsize=11, fontweight='bold', color=ACCENT_BLUE, pad=10)
                
                # Make percentage text white and bold
                for autotext in autotexts1:
                    autotext.set_color('white')
                    autotext.set_fontsize(7)
                    autotext.set_weight('bold')
            else:
                ax1.text(0.5, 0.5, 'No KPSEA Data', ha='center', va='center', fontsize=10, 
                        transform=ax1.transAxes, color='#95a5a6')
                ax1.set_title("KPSEA\n(Primary Grades 1-6)", fontsize=11, fontweight='bold', color=ACCENT_BLUE, pad=10)
            
            ax1.axis('equal')
            
            # KJSEA Pie Chart (Right)
            if kjsea_grades:
                grades_kjsea = list(kjsea_grades.keys())
                counts_kjsea = list(kjsea_grades.values())
                colors_kjsea = ['#e67e22', '#c0392b', '#16a085']
                
                wedges2, texts2, autotexts2 = ax2.pie(counts_kjsea, labels=grades_kjsea, autopct='%1.0f%%',
                                                       colors=colors_kjsea[:len(counts_kjsea)],
                                                       startangle=90, textprops={'fontsize': 8, 'weight': 'bold'})
                ax2.set_title("KJSEA\n(Secondary Grades 7-9)", fontsize=11, fontweight='bold', color=ACCENT_ORANGE, pad=10)
                
                # Make percentage text white and bold
                for autotext in autotexts2:
                    autotext.set_color('white')
                    autotext.set_fontsize(7)
                    autotext.set_weight('bold')
            else:
                ax2.text(0.5, 0.5, 'No KJSEA Data', ha='center', va='center', fontsize=10, 
                        transform=ax2.transAxes, color='#95a5a6')
                ax2.set_title("KJSEA\n(Secondary Grades 7-9)", fontsize=11, fontweight='bold', color=ACCENT_ORANGE, pad=10)
            
            ax2.axis('equal')
            
            # Adjust layout
            plt.tight_layout(pad=2)
            
            # Embed in tkinter
            mpl_canvas = FigureCanvasTkAgg(fig, master=graph_container)
            mpl_canvas.draw()
            mpl_canvas.get_tk_widget().pack(fill="both", expand=True)
        else:
            tk.Label(content_frame, text="No results recorded.", 
                    font=("Arial", 9, "italic"), bg=TEXT_WHITE, fg="#999999").pack(pady=6)

        # Move to next column/row
        col += 1
        if col >= 2:
            col = 0
            row += 1

    # Configure grid weights
    scrollable_frame.grid_rowconfigure(row, weight=1)
    scrollable_frame.grid_columnconfigure(0, weight=1)
    scrollable_frame.grid_columnconfigure(1, weight=1)

    canvas.pack(side="left", fill="both", expand=True, padx=0, pady=10)
    scrollbar.pack(side="right", fill="y", pady=10)


def show_exam_analysis_graphs():
    clear_main()
    tk.Label(main_frame,
             text="📈 Exam Analysis Graphs",
             font=("Arial", 18, "bold"),
             bg=BG_PRIMARY).pack(anchor="w", padx=20, pady=20)

    # controls: level, grade, mode (overall / subject)
    ctrl = tk.Frame(main_frame, bg=BG_PRIMARY)
    ctrl.pack(fill='x', padx=20, pady=8)
    tk.Label(ctrl, text="Level:", bg=BG_PRIMARY).pack(side='left')
    level_var = tk.StringVar(value='KPSEA')
    ttk.Combobox(ctrl, textvariable=level_var, values=['KPSEA','KJSEA'], width=8, state='readonly').pack(side='left', padx=6)
    tk.Label(ctrl, text='Grade:', bg=BG_PRIMARY).pack(side='left', padx=(12,0))
    grade_var = tk.IntVar(value=1)
    ttk.Combobox(ctrl, textvariable=grade_var, values=list(range(1,10)), width=6, state='readonly').pack(side='left', padx=6)

    mode_var = tk.StringVar(value='Overall')
    ttk.Combobox(ctrl, textvariable=mode_var, values=['Overall','Subject'], width=10, state='readonly').pack(side='left', padx=(12,6))

    def load_subjects():
        lvl = level_var.get()
        selected_grade = grade_var.get()
        subs = get_subjects_for_level_and_grade(lvl, selected_grade)
        subj_cb.config(values=subs)
        if subs:
            subject_var.set(subs[0])
        else:
            subject_var.set("")

    subjects = []
    subject_var = tk.StringVar(value='')
    subj_cb = ttk.Combobox(ctrl, textvariable=subject_var, values=subjects, width=20, state='readonly')
    subj_cb.pack(side='left', padx=6)

    def on_mode_change(*_):
        if mode_var.get() == 'Subject':
            subj_cb.config(state='readonly')
        else:
            subj_cb.config(state='disabled')
    mode_var.trace_add('write', on_mode_change)
    level_var.trace_add('write', lambda *_: load_subjects())
    load_subjects()

    plot_holder = {'frame': None}

    def plot_trend():
        grade = grade_var.get()
        mode = mode_var.get()
        # fetch exams ordered by date
        cursor.execute("SELECT id, exam_id, name, start_date FROM exams ORDER BY start_date")
        exams = cursor.fetchall()
        labels = []
        values = []
        if not exams:
            messagebox.showinfo('Info','No exams found')
            return

        if mode == 'Overall':
            for eid, code, name, start in exams:
                cursor.execute("""
                    SELECT AVG(t.total) FROM (
                        SELECT r.student_id, SUM(r.marks) as total
                        FROM results r
                        JOIN students s ON r.student_id = s.id
                        WHERE r.exam_id=? AND s.grade=?
                        GROUP BY r.student_id
                    ) t
                """, (eid, grade))
                avg = cursor.fetchone()[0] or 0
                labels.append(f"{code}")
                values.append(float(avg))
        else:
            subj = subject_var.get()
            if not subj:
                messagebox.showerror('Error','Select a subject')
                return
            cursor.execute("SELECT id FROM subjects WHERE name=?", (subj,))
            srow = cursor.fetchone()
            if not srow:
                messagebox.showerror('Error','Subject not found')
                return
            sid = srow[0]
            for eid, code, name, start in exams:
                cursor.execute("SELECT AVG(r.marks) FROM results r JOIN students s ON r.student_id=s.id WHERE r.exam_id=? AND r.subject_id=? AND s.grade=? AND r.marks IS NOT NULL", (eid, sid, grade))
                avg = cursor.fetchone()[0] or 0
                labels.append(f"{code}")
                values.append(float(avg))

        # clear previous plot
        if plot_holder['frame']:
            plot_holder['frame'].destroy()

        fig = plt.Figure(figsize=(11,5), dpi=100)
        ax = fig.add_subplot(111)
        x = list(range(len(labels)))
        # Plot as continuous line graph with circular markers
        ax.plot(x, values, marker='o', linewidth=2.5, markersize=8, color=ACCENT_BLUE, label=f"Grade {grade} {'Overall' if mode=='Overall' else subj}")
        ax.set_xticks(x)
        ax.set_xticklabels(labels, rotation=45, ha='right')
        ax.set_ylabel('Average Marks', fontsize=11, fontweight='bold')
        ax.set_xlabel('Exam (Chronological Order)', fontsize=11, fontweight='bold')
        ax.set_title(f'Grade {grade} Performance Trend Over Time ({mode} Mode)', fontsize=13, fontweight='bold', pad=15)
        ax.grid(True, linestyle='--', alpha=0.4, color='gray')
        ax.legend(loc='upper left', fontsize=10)
        # Ensure y-axis starts from 0 for proper context
        y_min = min(values) if values else 0
        y_max = max(values) if values else 100
        margin = (y_max - y_min) * 0.1 if (y_max - y_min) > 0 else 5
        ax.set_ylim(max(0, y_min - margin), y_max + margin)
        fig.tight_layout()

        frame = tk.Frame(main_frame, bg=BG_PRIMARY)
        frame.pack(fill='both', expand=True, padx=20, pady=12)
        plot_holder['frame'] = frame
        canvas = FigureCanvasTkAgg(fig, master=frame)
        canvas.draw()
        canvas.get_tk_widget().pack(fill='both', expand=True)

        def export_pdf():
            fname = filedialog.asksaveasfilename(defaultextension='.pdf', filetypes=[('PDF','*.pdf')], title='Save trend as PDF')
            if not fname:
                return
            from matplotlib.backends.backend_pdf import PdfPages
            pp = PdfPages(fname)
            pp.savefig(fig, bbox_inches='tight')
            pp.close()
            messagebox.showinfo('Saved', f'Saved trend to {fname}')

        btns = tk.Frame(main_frame, bg=BG_PRIMARY)
        btns.pack(fill='x', padx=20, pady=(0,12))
        tk.Button(btns, text='Export PDF', bg=ACCENT_GREEN, fg=TEXT_WHITE, command=export_pdf).pack(side='left')

    tk.Button(ctrl, text='Load Trend', bg=ACCENT_BLUE, fg=TEXT_WHITE, command=plot_trend).pack(side='left', padx=8)

def show_sub_reports(exam_id, exam_code):
    clear_main()
    tk.Button(main_frame, text="← Back", bg=ACCENT_PURPLE, fg=TEXT_WHITE, command=show_exam_reports).pack(anchor="w", padx=20, pady=10)
