    tk.Button(btnframe, text="📑 Grade Report Forms", bg=ACCENT_BLUE, fg=TEXT_WHITE, padx=20, pady=8, command=lambda: show_grade_report(exam_id)).pack(side="left", padx=5)
    tk.Button(btnframe, text="🏆 Student Ranking", bg=ACCENT_GREEN, fg=TEXT_WHITE, padx=20, pady=8, command=lambda: show_student_ranking(exam_id)).pack(side="left", padx=5)
