        improved_detail = tk.Frame(improved_frame, bg=lighten_color(ACCENT_GREEN, 0.3))
        improved_detail.pack(fill="x", padx=12, pady=(0, 8))
        
        tk.Label(improved_detail, text=f"Student Name: {most_improved_name} | Improvement: +{max_improvement:.0f} marks", 
                font=("Arial", 9, "bold"), bg=lighten_color(ACCENT_GREEN, 0.3), fg=TEXT_DARK).pack(anchor="w")
        
        # === SIGNATURE AND REMARKS SECTION ===
        sig_section = tk.Frame(a4_frame, bg=TEXT_WHITE)
        sig_section.pack(fill="x", padx=16, pady=12, side="bottom")
        
        # Divider before signature section
        ttk.Separator(sig_section, orient="horizontal").pack(fill="x", pady=(0, 10))
        
        # Title
        tk.Label(sig_section, text="OFFICIAL SIGN-OFF", font=("Arial", 10, "bold"), bg=TEXT_WHITE, fg=ACCENT_BLUE).pack(anchor="w", pady=(0, 8))
        
        # Signature area (top section)
        sig_area = tk.Frame(sig_section, bg=TEXT_WHITE, relief="solid", bd=1)
