        tk.Label(left_sig, text="Headteacher Signature:", font=("Arial", 9, "bold"), bg=TEXT_WHITE, fg=TEXT_DARK).pack(anchor="w", pady=(0, 35))
        sig_line = tk.Frame(left_sig, bg=TEXT_DARK, height=1)
        sig_line.pack(fill="x", pady=(0, 5))
