    def view_performance_summary():
        """Show student performance summary across all exams"""
        options_popup.destroy()
        
        summary_popup = tk.Toplevel(root)
        summary_popup.title(f"Performance Summary - {name}")
        summary_popup.geometry("600x500")
        summary_popup.transient(root)
        summary_popup.grab_set()
        
        # Header
        header_frame = tk.Frame(summary_popup, bg=ACCENT_BLUE)
        header_frame.pack(fill="x")
        tk.Label(header_frame, text=f"📊 Performance Summary", font=("Arial", 14, "bold"), bg=ACCENT_BLUE, fg=TEXT_WHITE).pack(pady=10)
        tk.Label(header_frame, text=f"{name} ({admission}) - {level} Grade {grade}", font=("Arial", 11), bg=ACCENT_BLUE, fg=TEXT_WHITE).pack(pady=(0, 10))
        
        # Content frame
        canvas = tk.Canvas(summary_popup, bg=BG_PRIMARY, highlightthickness=0)
        scrollbar = ttk.Scrollbar(summary_popup, orient="vertical", command=canvas.yview)
        scrollable_frame = tk.Frame(canvas, bg=BG_PRIMARY)
        
        scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )
        
        canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        canvas.configure(yscrollcommand=scrollbar.set)
        
        # Fetch exam performance data
        cursor.execute("""
            SELECT e.exam_id, e.name, e.start_date, 
                   COALESCE(SUM(r.marks), 0) as total,
                   COUNT(r.subject_id) as subject_count,
                   AVG(r.marks) as average
            FROM exams e
            LEFT JOIN results r ON e.id = r.exam_id AND r.student_id = ?
            GROUP BY e.id, e.exam_id, e.name, e.start_date
            ORDER BY e.start_date DESC
        """, (student_id,))
        exam_data = cursor.fetchall()
        
        if not exam_data:
            tk.Label(scrollable_frame, text="No exam records found", font=("Arial", 11, "italic"), bg=BG_PRIMARY, fg="#999999").pack(pady=20)
        else:
            tk.Label(scrollable_frame, text="Exam Performance", font=("Arial", 12, "bold"), bg=BG_PRIMARY, fg=ACCENT_GREEN).pack(anchor="w", padx=15, pady=10)
            
            # Table-like display
            for exam_id, exam_name, exam_date, total, subj_count, avg in exam_data:
                exam_frame = tk.Frame(scrollable_frame, bg=lighten_color(BG_PRIMARY, 0.05), relief="solid", bd=1)
                exam_frame.pack(fill="x", padx=15, pady=6)
                
                # Exam name and date
                tk.Label(exam_frame, text=f"📝 {exam_name}", font=("Arial", 10, "bold"), bg=lighten_color(BG_PRIMARY, 0.05), fg=TEXT_DARK).pack(anchor="w", padx=10, pady=(8, 2))
                tk.Label(exam_frame, text=f"Date: {exam_date}", font=("Arial", 9), bg=lighten_color(BG_PRIMARY, 0.05), fg="#666666").pack(anchor="w", padx=10, pady=(0, 8))
                
                # Stats row
                stats_frame = tk.Frame(exam_frame, bg=lighten_color(BG_PRIMARY, 0.05))
                stats_frame.pack(fill="x", padx=10, pady=(0, 8))
                
                tk.Label(stats_frame, text=f"Total: {total}", font=("Arial", 9, "bold"), bg=lighten_color(BG_PRIMARY, 0.05), fg=ACCENT_BLUE).pack(side="left", padx=(0, 20))
                tk.Label(stats_frame, text=f"Subjects: {subj_count}", font=("Arial", 9, "bold"), bg=lighten_color(BG_PRIMARY, 0.05), fg=ACCENT_GREEN).pack(side="left", padx=(0, 20))
                tk.Label(stats_frame, text=f"Average: {avg:.1f if avg else 0}", font=("Arial", 9, "bold"), bg=lighten_color(BG_PRIMARY, 0.05), fg=ACCENT_PURPLE).pack(side="left")
        
        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        
        tk.Button(summary_popup, text="Close", bg=ACCENT_BLUE, fg=TEXT_WHITE, command=summary_popup.destroy).pack(pady=10)
    
