            tk.Label(info_frame, text=f"📝 {exam_name}", font=("Arial", 10, "bold"), bg=lighten_color(BG_PRIMARY, 0.05), fg=TEXT_DARK).pack(anchor="w", pady=(0, 3))
            tk.Label(info_frame, text=f"Code: {exam_code} | Date: {exam_date}", font=("Arial", 9), bg=lighten_color(BG_PRIMARY, 0.05), fg="#666666").pack(anchor="w")
            
