    last_adm_info = tk.StringVar(value="Click the button below to generate the last admission record.")
    tk.Label(last_adm_frame, textvariable=last_adm_info, font=("Arial", 10), bg="#FFE0B2", fg="#BF360C", justify="left", wraplength=760).pack(anchor="w", padx=15, pady=(0, 8))

    def generate_last_admission():
        try:
            # Ensure database connection and tables exist
            global conn, cursor
            if conn is None:
                # Create database directory if it doesn't exist
                os.makedirs(os.path.dirname(DB_FILE), exist_ok=True)
                conn = sqlite3.connect(DB_FILE)
                cursor = conn.cursor()
            ensure_tables()
            
            cursor.execute("""
                SELECT admission_number, student_name, level, grade, stream, parent_name, parent_phone, parent_id, student_details, created_at
                FROM students
                ORDER BY created_at DESC, id DESC
                LIMIT 1
            """)
            row = cursor.fetchone()
            if not row:
                last_adm_info.set("No students found. Please register a student first.")
                return

            admission_number, student_name, level, grade, stream, parent_name, parent_phone, parent_id, student_details, created_at = row
            details = (
                f"Last Admission: {admission_number}\n"
                f"Name: {student_name}\n"
                f"Level: {level} | Grade: {grade} | Stream: {stream}\n"
                f"Parent: {parent_name} | Phone: {parent_phone}\n"
                f"Additional Details: {student_details or 'N/A'}\n"
                f"Registered: {created_at}"
            )
            last_adm_info.set(details)
        except Exception as e:
            last_adm_info.set(f"Error retrieving last admission record: {e}")

