# Start the application
if __name__ == "__main__":
    # Initialize database connection and tables
    conn = sqlite3.connect(DB_FILE)
    cursor = conn.cursor()
    ensure_tables()
    ensure_default_teacher()
    ensure_default_subjects()
    
    # Load and apply display settings (theme and font size)
    display_settings = load_display_settings()
    apply_theme(display_settings.get("theme", "Dark"))
    apply_font_size(display_settings.get("font_size", "Normal"))
    
    if len(sys.argv) > 1 and sys.argv[1] == "--web-only":
        # Run only the web server
        if FLASK_AVAILABLE:
            app = create_flask_app()
            if app:
                print("Starting Flask web server on http://localhost:5000")
                app.run(host='0.0.0.0', port=5000, debug=True, use_reloader=False)
            else:
                print("Failed to create Flask app")
        else:
            print("Flask is not available")
    else:
        show_login_screen()
        root.mainloop()

